-- Schema for Domain: finance | Business: Retail | Version: v1_mvm
-- Generated on: 2026-05-04 13:27:41

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `retail_ecm`.`finance` COMMENT 'SSOT for financial accounting, general ledger, accounts payable/receivable, revenue recognition (ASC 606), P&L reporting, EBITDA tracking, budgeting, forecasting, COGS, gross margin, lease accounting (ASC 842), and financial close processes. Integrates with SAP S/4HANA FI/CO modules for enterprise financial management and FASB-compliant regulatory reporting.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `retail_ecm`.`finance`.`cost_center` (
    `cost_center_id` BIGINT COMMENT 'Unique surrogate identifier for the cost center record in the Databricks Silver Layer. Primary key generated by the lakehouse ingestion pipeline from SAP S/4HANA FI/CO.',
    `dc_facility_id` BIGINT COMMENT 'Reference to the distribution center (DC) associated with this cost center, when the cost center represents a DC or fulfillment location. Supports supply chain cost allocation and COGS tracking.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Cost centers in SAP S/4HANA reference a primary GL account (cost element) for expense postings and commitment management. The existing gl_account_code STRING is a denormalized reference that should be',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: In SAP S/4HANA CO, every cost center is assigned to exactly one profit center for P&L reporting and segment reporting. This is a fundamental SAP controlling master data relationship. The existing prof',
    `actual_ytd_amount` DECIMAL(18,2) COMMENT 'Cumulative actual expenses posted to this cost center from the start of the fiscal year to the current reporting period. Sourced from SAP FI/CO actuals. Used for budget variance, EBITDA tracking, and financial close reporting.',
    `allocation_method` STRING COMMENT 'Method used to allocate or distribute costs from this cost center to other cost objects (e.g., direct posting, SAP assessment cycle, distribution cycle, activity-based costing). Governs how overhead is spread across stores, DCs, and product categories.. Valid values are `direct|assessment|distribution|activity_based|statistical`',
    `annual_budget_amount` DECIMAL(18,2) COMMENT 'Total approved annual budget allocated to this cost center for the current fiscal year, expressed in the cost center currency. Used for Open to Buy (OTB) tracking, budget vs. actuals variance analysis, and financial planning.',
    `budget_fiscal_year` STRING COMMENT 'The fiscal year (four-digit integer, e.g., 2025) to which the annual budget amount applies. Aligns with the SAP fiscal year variant for period-based budget vs. actuals comparison.',
    `business_area_code` STRING COMMENT 'SAP Business Area (GSBER) to which this cost center is assigned. Enables cross-company-code P&L reporting by business segment (e.g., Grocery, Apparel, E-Commerce). Supports FASB ASC 280 segment disclosures.. Valid values are `^[A-Z0-9]{1,4}$`',
    `commitment_amount` DECIMAL(18,2) COMMENT 'Total open purchase order and contract commitment amounts encumbered against this cost centers budget but not yet invoiced. Supports available budget calculation and OTB management in SAP CO-OM.',
    `company_code` STRING COMMENT 'SAP Company Code (BUKRS) representing the legal entity to which this cost center is assigned. Used for statutory financial reporting, P&L consolidation, and FASB-compliant revenue and expense recognition.. Valid values are `^[A-Z0-9]{1,4}$`',
    `controlling_area_code` STRING COMMENT 'SAP Controlling Area (KOKRS) to which this cost center belongs. The controlling area defines the organizational unit within which cost accounting is performed. All cost centers within a controlling area share the same chart of accounts and fiscal year variant.. Valid values are `^[A-Z0-9]{1,4}$`',
    `cost_center_category` STRING COMMENT 'SAP cost center category (KOSAR) that controls which business transactions are allowed for this cost center (e.g., A for general cost centers, E for production cost centers). Governs posting rules in FI/CO.. Valid values are `^[A-Z0-9]{1,2}$`',
    `cost_center_code` STRING COMMENT 'The externally-known alphanumeric code that uniquely identifies the cost center within the controlling area, as defined in SAP S/4HANA CO module (field: KOSTL). Used in P&L reporting, budget allocation, and expense posting.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `cost_center_description` STRING COMMENT 'Long-form description of the cost centers business purpose, scope of expenses, and organizational context. Corresponds to SAP S/4HANA field LTEXT.',
    `cost_center_level` STRING COMMENT 'Numeric level of this cost center within the enterprise cost center hierarchy (1 = top/enterprise, higher numbers = more granular). Enables hierarchical roll-up queries for consolidated P&L and EBITDA reporting.',
    `cost_center_name` STRING COMMENT 'Human-readable name of the cost center as maintained in SAP S/4HANA (field: KTEXT). Describes the organizational unit, e.g., Store 042 - Chicago Loop, DC Atlanta, Corporate Finance.',
    `cost_center_status` STRING COMMENT 'Current lifecycle status of the cost center. active = open for postings; locked = temporarily blocked for new postings (SAP lock indicator); inactive = no longer in use; pending = awaiting activation; archived = closed and retained for historical reporting.. Valid values are `active|inactive|locked|pending|archived`',
    `cost_center_type` STRING COMMENT 'Classification of the cost center by organizational unit type. Drives expense allocation rules, budget templates, and P&L reporting hierarchies. [ENUM-REF-CANDIDATE: store|distribution_center|corporate|regional_office|ecommerce|shared_services|manufacturing|logistics — promote to reference product]. Valid values are `store|distribution_center|corporate|regional_office|ecommerce|shared_services`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country where this cost centers organizational unit is physically located. Used for multi-country P&L reporting, tax jurisdiction assignment, and GDPR/CCPA data residency compliance.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this cost center record was first created in the source system (SAP S/4HANA CO). Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX per enterprise data standards. Used for audit trail and data lineage.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the cost centers controlling area currency (SAP field: WAERS). All budget, actual, and commitment amounts for this cost center are expressed in this currency.. Valid values are `^[A-Z]{3}$`',
    `fiscal_year_variant` STRING COMMENT 'SAP fiscal year variant (PERIV) assigned to this cost centers controlling area. Defines the fiscal calendar (e.g., K4 for calendar year, V3 for April–March). Critical for period-based budget vs. actuals comparison and FASB-compliant financial close.. Valid values are `^[A-Z0-9]{1,2}$`',
    `functional_area_code` STRING COMMENT 'SAP Functional Area (FKBER) classifying the cost center by business function (e.g., Sales, Administration, Production, Logistics). Used for cost-of-sales accounting and functional P&L reporting per FASB ASC 220.. Valid values are `^[A-Z0-9]{1,16}$`',
    `headcount_budget` STRING COMMENT 'Approved headcount (number of full-time equivalent employees) budgeted for this cost center in the current fiscal year. Used for workforce cost planning, Workday HCM integration, and labor cost as a percentage of sales analysis.',
    `hierarchy_area` STRING COMMENT 'Node within the standard cost center hierarchy (SAP field: KOSAR/KHINR) that positions this cost center in the enterprise organizational tree. Used for roll-up reporting in P&L, EBITDA tracking, and budget consolidation.',
    `internal_order_code` STRING COMMENT 'SAP Internal Order (AUFNR) code linked to this cost center for detailed cost monitoring of specific activities or projects (e.g., marketing campaigns, store remodels). Enables granular expense tracking beyond standard cost center reporting.. Valid values are `^[A-Z0-9_-]{1,12}$`',
    `is_locked_for_posting` BOOLEAN COMMENT 'Indicates whether this cost center is currently locked against new financial postings (SAP lock indicator). True = no new postings allowed; False = postings permitted. Used during period-end close and cost center restructuring.',
    `is_statistical` BOOLEAN COMMENT 'Indicates whether this cost center is a statistical cost center (SAP field: STAT). Statistical cost centers receive postings for informational/reporting purposes only and do not carry real costs. True = statistical; False = real cost center.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this cost center record in the source system (SAP S/4HANA CO). Used for change data capture (CDC), audit trail, and financial close reconciliation.',
    `region_code` STRING COMMENT 'Internal regional classification code for the cost centers geographic location (e.g., NORTHEAST, WEST, EMEA). Supports regional P&L roll-up, comp sales (SSS) analysis, and regional budget allocation.. Valid values are `^[A-Z0-9_-]{1,10}$`',
    `source_system_code` STRING COMMENT 'Identifier of the operational system of record from which this cost center master record was sourced (e.g., SAP_S4HANA). Supports data lineage, MDM golden record management via Informatica MDM, and audit traceability.. Valid values are `SAP_S4HANA|ORACLE_ERP|WORKDAY|MANUAL`',
    `tax_jurisdiction_code` STRING COMMENT 'Tax jurisdiction code assigned to this cost center for tax calculation and reporting purposes (SAP field: TXJCD). Determines applicable sales tax, VAT, and local tax rates for expense postings. Required for FTC pricing transparency and FDA compliance for grocery cost centers.. Valid values are `^[A-Z0-9_-]{1,15}$`',
    `wbs_element_code` STRING COMMENT 'SAP Work Breakdown Structure (WBS) element code associated with this cost center for project-based cost tracking. Used when the cost center is linked to a capital project (e.g., store renovation, DC expansion) for CAPEX vs. OPEX classification per FASB ASC 842.. Valid values are `^[A-Z0-9._-]{1,24}$`',
    `valid_from` DATE COMMENT 'Start date of the cost centers validity period (SAP field: DATAB). The cost center is open for expense postings from this date. Supports fiscal year-aligned budget and actuals reporting.',
    `valid_to` DATE COMMENT 'End date of the cost centers validity period (SAP field: DATBI). After this date, no new postings are permitted. Null or 9999-12-31 indicates an open-ended cost center with no planned closure.',
    CONSTRAINT pk_cost_center PRIMARY KEY(`cost_center_id`)
) COMMENT 'Master record for organizational cost centers used in SAP S/4HANA FI/CO for expense allocation, P&L reporting, and budget tracking. Each cost center represents a distinct organizational unit (store, DC, corporate department) responsible for incurring costs. Includes cost center hierarchy, responsible manager, controlling area, profit center assignment, and validity periods.';

CREATE OR REPLACE TABLE `retail_ecm`.`finance`.`profit_center` (
    `profit_center_id` BIGINT COMMENT 'Unique surrogate identifier for the profit center master record in the Databricks Silver Layer. Primary key for the profit_center data product. Role: MASTER_RESOURCE.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: In SAP S/4HANA FI-CO, each profit center references a retained earnings GL account for year-end closing postings. The existing gl_account_code STRING is a denormalized reference that should be replace',
    `annual_cogs_budget` DECIMAL(18,2) COMMENT 'Planned annual Cost of Goods Sold (COGS) budget for this profit center. Used to calculate budgeted gross margin and GMROI targets. Expressed in the currency defined by currency_code.',
    `annual_opex_budget` DECIMAL(18,2) COMMENT 'Planned annual operating expense (OPEX) budget for this profit center, excluding COGS. Includes store labor, occupancy, marketing, and overhead. Used for EBITDA planning and P&L variance reporting. Expressed in the currency defined by currency_code.',
    `annual_revenue_budget` DECIMAL(18,2) COMMENT 'Planned annual revenue target for this profit center in the profit center currency. Used for P&L variance analysis, comp sales (SSS) benchmarking, and EBITDA forecasting. Sourced from SAP CO-PCA budget planning. Expressed in the currency defined by currency_code.',
    `asc280_reportable_flag` BOOLEAN COMMENT 'Indicates whether this profit center qualifies as a reportable segment under FASB ASC 280 (Segment Reporting) based on the 10% quantitative thresholds for revenue, profit/loss, or assets (True = reportable segment). Drives external financial disclosure requirements.',
    `budget_period` STRING COMMENT 'The fiscal year or fiscal year-period (YYYY or YYYY-MM) for which the current budget is active for this profit center. Used in Open to Buy (OTB) planning, financial forecasting, and variance analysis against actuals.. Valid values are `^[0-9]{4}(-[0-9]{2})?$`',
    `business_area_code` STRING COMMENT 'SAP business area code representing a distinct area of operations for which an internal balance sheet and P&L can be drawn up (e.g., RETAIL, WHOLESALE, ECOM). Supports cross-company-code reporting and segment disclosures.. Valid values are `^[A-Z0-9]{1,4}$`',
    `channel_type` STRING COMMENT 'Retail channel classification for this profit center indicating how revenue is generated: physical_store (brick-and-mortar), ecommerce (digital), omnichannel (BOPIS/ROPIS), wholesale, marketplace (third-party platform), dark_store (fulfillment-only). Enables channel-level P&L and comp sales (SSS) analysis.. Valid values are `physical_store|ecommerce|omnichannel|wholesale|marketplace|dark_store`',
    `company_code` STRING COMMENT 'SAP FI company code representing the legal entity to which this profit center belongs. Determines the chart of accounts, fiscal year variant, and currency for financial postings. Required for intercompany transfer pricing and legal entity P&L.. Valid values are `^[A-Z0-9]{1,6}$`',
    `controlling_area_code` STRING COMMENT 'SAP Controlling Area code to which this profit center belongs (e.g., US01, EU01). The controlling area defines the organizational unit within which cost and profit center accounting is performed. Required for all CO-PCA postings.. Valid values are `^[A-Z0-9]{1,4}$`',
    `cost_center_code` STRING COMMENT 'SAP CO cost center code linked to this profit center for overhead cost allocation and internal management accounting. Enables COGS and operating expense tracking at the profit center level for EBITDA calculation.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code for the country in which this profit center operates (e.g., USA, GBR, CAN). Required for multi-national tax reporting, transfer pricing compliance, and GDPR/CCPA data residency.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this profit center master record was first created in the source system (SAP CO-PCA). Supports audit trail, data lineage, and financial close governance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX. Satisfies MASTER_RESOURCE RECORD_AUDIT_CREATED category.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the profit centers local management reporting currency (e.g., USD, EUR, GBP). All revenue, COGS, gross margin, and EBITDA figures for this profit center are reported in this currency. Satisfies MASTER_RESOURCE MEASUREMENT_OR_VALUE category (principal quantitative context).. Valid values are `^[A-Z]{3}$`',
    `deactivation_date` DATE COMMENT 'Date on which this profit center was deactivated or archived. Null if the profit center is currently active. Used for historical P&L analysis, store closure reporting, and comp sales (SSS) exclusion logic.',
    `elimination_flag` BOOLEAN COMMENT 'Indicates whether intercompany transactions for this profit center are subject to elimination during consolidated financial reporting (True = elimination required). Used in group consolidation to remove internal P&L and balance sheet effects per FASB ASC 810.',
    `fiscal_year_variant` STRING COMMENT 'SAP fiscal year variant code defining the fiscal calendar for this profit center (e.g., K4 for calendar year, V3 for April–March). Determines period-end close dates, budget cycles, and financial reporting periods for EBITDA and P&L tracking.. Valid values are `^[A-Z0-9]{1,4}$`',
    `functional_area_code` STRING COMMENT 'SAP functional area code classifying the business function of this profit center (e.g., SALES, PRODUCTION, ADMIN, DISTRIBUTION). Used for cost-of-sales accounting and P&L by function reporting per IFRS/GAAP.. Valid values are `^[A-Z0-9_-]{1,16}$`',
    `hierarchy_node_code` STRING COMMENT 'Code of the standard hierarchy node to which this profit center is assigned in SAP CO-PCA. Enables rollup P&L reporting across organizational levels (e.g., store → region → banner → enterprise). Used for segment reporting per ASC 280.. Valid values are `^[A-Z0-9_-]{1,30}$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this profit center master record. Used for change data capture (CDC), MDM synchronization, and audit trail maintenance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `lease_accounting_flag` BOOLEAN COMMENT 'Indicates whether this profit center has active lease obligations subject to ASC 842 lease accounting (True = lease obligations exist). Triggers right-of-use (ROU) asset and lease liability recognition in the financial close process for store and DC profit centers.',
    `mdm_source_system` STRING COMMENT 'Identifies the authoritative source system from which this profit center master record was originated or last mastered (e.g., SAP_S4HANA, INFORMATICA_MDM). Supports data lineage, MDM golden record management, and audit traceability.. Valid values are `SAP_S4HANA|INFORMATICA_MDM|ORACLE_ORMS|MANUAL`',
    `posting_block_flag` BOOLEAN COMMENT 'Indicates whether financial postings to this profit center are currently blocked (True = blocked, False = open). Set during financial close periods, audits, or when a profit center is being restructured. Prevents erroneous postings during sensitive periods.',
    `profit_center_category` STRING COMMENT 'Management accounting classification indicating the primary financial role of the profit center: revenue (generates external revenue), cost (internal cost allocation only), investment (capital-intensive with ROI tracking), service (shared service provider). Drives transfer pricing rules and internal P&L treatment.. Valid values are `revenue|cost|investment|service`',
    `profit_center_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the profit center within the controlling area, as defined in SAP S/4HANA CO-PCA (e.g., PC_STORE_0042, PC_ECOM_US). Used in journal entries, cost allocations, and management reports. Satisfies MASTER_RESOURCE BUSINESS_IDENTIFIER category.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    `profit_center_description` STRING COMMENT 'Detailed business description of the profit centers purpose, scope, and the business unit it represents. Provides context for financial analysts, auditors, and management reporting consumers.',
    `profit_center_level` STRING COMMENT 'Numeric level of this profit center within the management accounting hierarchy (e.g., 1 = enterprise, 2 = banner, 3 = region, 4 = store). Used for hierarchical P&L rollup, drill-down reporting, and segment aggregation.',
    `profit_center_name` STRING COMMENT 'Human-readable name of the profit center (e.g., Chicago Flagship Store, US E-Commerce Channel, Private Label Apparel). Used in P&L reports, dashboards, and management presentations. Satisfies MASTER_RESOURCE IDENTITY_LABEL category.',
    `profit_center_status` STRING COMMENT 'Current lifecycle state of the profit center master record. active — open for postings; inactive — temporarily closed; locked — blocked for new postings (e.g., during financial close); pending — awaiting activation; archived — historical record, no postings allowed. Satisfies MASTER_RESOURCE LIFECYCLE_STATUS category.. Valid values are `active|inactive|locked|pending|archived`',
    `profit_center_type` STRING COMMENT 'Classification of the autonomous business unit represented by this profit center. Determines the nature of P&L reporting: store (physical retail location), channel (e-commerce, BOPIS, DSD), product_line (private label, electronics, apparel), banner (hypermarket, discount outlet), region (geographic grouping), corporate (shared services). Satisfies MASTER_RESOURCE CLASSIFICATION_OR_TYPE category.. Valid values are `store|channel|product_line|banner|region|corporate`',
    `region_code` STRING COMMENT 'Geographic region code to which this profit center belongs (e.g., NORTHEAST, MIDWEST, WEST_COAST, EMEA). Used for regional P&L rollup, comp sales analysis, and management reporting by geography.. Valid values are `^[A-Z0-9_-]{1,10}$`',
    `responsible_manager` STRING COMMENT 'Full name or employee ID of the manager accountable for this profit centers financial performance. Used in management reporting, budget approval workflows, and P&L accountability assignments in SAP CO-PCA.',
    `segment_code` STRING COMMENT 'Financial reporting segment assigned to this profit center per FASB ASC 280 (Segment Reporting). Maps profit centers to reportable segments (e.g., GROCERY, APPAREL, ECOMMERCE, INTERNATIONAL) for external financial disclosures and SEC filings.. Valid values are `^[A-Z0-9_-]{1,20}$`',
    `short_name` STRING COMMENT 'Abbreviated display name for the profit center used in space-constrained reports, POS system displays, and financial dashboards (e.g., CHI-FLAGSHIP, ECOM-US).. Valid values are `^.{1,20}$`',
    `store_number` STRING COMMENT 'Physical store identifier associated with this profit center when profit_center_type is store. Links to the store master for footfall, planogram, and comp sales (SSS) reporting. Null for non-store profit centers.. Valid values are `^[A-Z0-9-]{1,15}$`',
    `transfer_price_flag` BOOLEAN COMMENT 'Indicates whether transfer pricing rules apply to transactions involving this profit center (True = transfer pricing active). Relevant for intercompany transactions between profit centers, particularly for cross-border operations subject to OECD transfer pricing guidelines.',
    `valid_from_date` DATE COMMENT 'Date from which this profit center is valid and open for financial postings in SAP CO-PCA. Defines the start of the profit centers active period for time-dependent master data management and fiscal year planning.',
    `valid_to_date` DATE COMMENT 'Date until which this profit center is valid for financial postings. After this date, the profit center is locked for new transactions. Null indicates an open-ended validity period. Used for profit center lifecycle management and financial close.',
    CONSTRAINT pk_profit_center PRIMARY KEY(`profit_center_id`)
) COMMENT 'Master record for profit centers representing autonomous business units (store, product line, channel, banner) for internal management accounting in SAP S/4HANA CO-PCA. Enables internal P&L reporting tracking revenue, COGS, gross margin, operating expenses, and EBITDA at the profit center level. Includes profit center hierarchy, controlling area, segment assignment, and responsible manager. Supports segment reporting per ASC 280, transfer pricing, and management decision-making.';

CREATE OR REPLACE TABLE `retail_ecm`.`finance`.`gl_account` (
    `gl_account_id` BIGINT COMMENT 'Unique surrogate identifier for the general ledger account record in the Databricks Silver Layer. Primary key for the gl_account master data product.',
    `account_group` STRING COMMENT 'SAP account group (KTOKS) that controls the number range and field selection for the GL account. Groups accounts by functional category such as cash accounts, receivables, payables, revenue accounts, COGS accounts, and operating expense accounts. [ENUM-REF-CANDIDATE: cash|receivables|payables|revenue|cogs|opex|assets|liabilities|equity|statistical — promote to reference product]',
    `account_long_name` STRING COMMENT 'Extended descriptive name of the GL account providing full business context beyond the short name. Used in detailed financial reporting, audit documentation, and regulatory disclosures.',
    `account_name` STRING COMMENT 'Human-readable short description of the GL account as maintained in SAP S/4HANA (SKAT table). Used in financial statements, P&L reports, and EBITDA dashboards for display and labeling purposes.',
    `account_number` STRING COMMENT 'The externally-known GL account number as defined in the SAP S/4HANA chart of accounts (SKA1/SKB1 tables). Used in all financial postings, journal entries, and regulatory reporting. Typically a 6–10 digit numeric code aligned to the companys account numbering scheme.. Valid values are `^[0-9]{1,10}$`',
    `account_status` STRING COMMENT 'Current lifecycle status of the GL account. active permits financial postings; blocked prevents new postings while retaining history; marked_for_deletion flags the account for archival after period-end close; inactive denotes accounts no longer in use. Maps to SAP field XSPEB (posting block) and XLOEV (deletion flag).. Valid values are `active|blocked|marked_for_deletion|inactive`',
    `account_type` STRING COMMENT 'Fundamental classification of the GL account per GAAP balance sheet and income statement structure. Drives financial statement placement: asset/liability/equity for balance sheet; revenue/expense for P&L. Maps to SAP field KTOKS (account group) and XBILK (balance sheet indicator).. Valid values are `asset|liability|equity|revenue|expense`',
    `alternative_account_number` STRING COMMENT 'Country-specific or group-level alternative account number used for local statutory reporting or group consolidation mapping. Enables cross-mapping between the operational chart of accounts and a group/statutory chart of accounts. Maps to SAP field ALTKT in SKB1.',
    `balance_sheet_account` BOOLEAN COMMENT 'Indicates whether this account is a balance sheet account (True) or a P&L income statement account (False). Balance sheet accounts carry forward balances at year-end; P&L accounts are closed to retained earnings. Maps to SAP field XBILK in SKA1.',
    `chart_of_accounts_code` STRING COMMENT 'Identifier for the chart of accounts to which this GL account belongs in SAP S/4HANA (e.g., INT for international, CAUS for US GAAP). A single enterprise may maintain multiple charts of accounts for group vs. local reporting.. Valid values are `^[A-Z0-9]{1,4}$`',
    `commitment_management` BOOLEAN COMMENT 'Indicates whether commitment management (budget encumbrance) is active (True) for this GL account. When enabled, purchase orders and purchase requisitions create budget commitments against this account, supporting Open-to-Buy (OTB) budget control in merchandise planning.',
    `company_code` STRING COMMENT 'SAP S/4HANA company code representing the legal entity or organizational unit for which this GL account is active. Drives financial statement segregation, tax reporting, and intercompany reconciliation.. Valid values are `^[A-Z0-9]{1,4}$`',
    `cost_element_category` STRING COMMENT 'Indicates whether this GL account is linked to a CO (Controlling) cost element and its category. primary cost elements correspond to P&L accounts (e.g., COGS, operating expenses); secondary are internal allocation accounts; not_applicable for balance sheet accounts. Drives EBITDA and P&L cost center reporting.. Valid values are `primary|secondary|not_applicable`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this GL account master record was first created in the source system (SAP S/4HANA). Supports audit trail requirements, data lineage tracking, and financial close process governance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the account currency in which balances are maintained (e.g., USD, EUR, GBP). If set, postings to this account must be made in this currency. Maps to SAP field WAERS in SKB1.. Valid values are `^[A-Z]{3}$`',
    `deferred_revenue_indicator` BOOLEAN COMMENT 'Indicates whether this GL account is used to record deferred revenue (True), such as gift card liabilities, loyalty point deferrals, or advance payments not yet recognized under ASC 606. Supports balance sheet classification and revenue recognition scheduling.',
    `effective_from_date` DATE COMMENT 'The date from which this GL account became active and available for financial postings. Supports temporal validity tracking for chart of accounts changes during fiscal year transitions and regulatory reporting periods.',
    `effective_to_date` DATE COMMENT 'The date after which this GL account is no longer valid for new financial postings. Null indicates an open-ended account with no planned expiry. Used to manage account lifecycle during chart of accounts restructuring and fiscal year-end close.',
    `fasb_classification` STRING COMMENT 'FASB Accounting Standards Codification (ASC) topic or subtopic to which this GL account is primarily aligned (e.g., ASC 606 for revenue recognition accounts, ASC 842 for lease liability/ROU asset accounts, ASC 330 for inventory/COGS accounts). Supports FASB-compliant regulatory reporting and audit readiness. [ENUM-REF-CANDIDATE: ASC_606|ASC_842|ASC_330|ASC_350|ASC_360|ASC_420 — promote to reference product]',
    `field_status_group` STRING COMMENT 'SAP field status group code (e.g., G001, G004) assigned to this GL account that controls which fields are required, optional, or suppressed during document entry. Enforces data quality and completeness rules at the point of financial posting.. Valid values are `^[A-Z][0-9]{3}$`',
    `financial_statement_version` STRING COMMENT 'SAP Financial Statement Version (FSV) code that determines how this account is grouped and displayed in statutory financial statements (balance sheet, P&L). Supports GAAP, IFRS, and management reporting views. Maps to SAP table T011.. Valid values are `^[A-Z0-9]{1,4}$`',
    `fs_item_code` STRING COMMENT 'The financial statement line item code to which this GL account is assigned within the Financial Statement Version. Enables aggregation of multiple GL accounts into a single P&L or balance sheet line for external reporting and FASB-compliant disclosures.',
    `functional_area` STRING COMMENT 'SAP functional area classification that segments costs by business function for cost-of-sales P&L reporting (e.g., SALES, ADMIN, LOGISTICS, MARKETING, STORE_OPS). Enables functional income statement presentation per IFRS IAS 1 and management reporting. [ENUM-REF-CANDIDATE: sales|administration|logistics|marketing|store_operations|ecommerce|supply_chain — promote to reference product]',
    `house_bank_account` BOOLEAN COMMENT 'Indicates whether this GL account is a bank account (True) linked to a house bank in SAP FI-TR (Treasury). Bank GL accounts are used for cash management, bank reconciliation, and PCI DSS-compliant payment processing.',
    `intercompany_account` BOOLEAN COMMENT 'Indicates whether this GL account is designated for intercompany transactions (True) between legal entities within the retail group. Intercompany accounts are eliminated during group consolidation. Maps to SAP intercompany account configuration.',
    `last_changed_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this GL account master record in SAP S/4HANA. Used for change detection in ETL pipelines, audit compliance, and Sarbanes-Oxley (SOX) internal control documentation.',
    `lease_account_type` STRING COMMENT 'Classifies the GL accounts role under FASB ASC 842 lease accounting. rou_asset identifies Right-of-Use asset accounts for operating and finance leases; lease_liability identifies corresponding liability accounts; lease_expense identifies amortization/interest expense accounts; not_applicable for non-lease accounts. Critical for ASC 842 compliance reporting in retail store lease portfolios.. Valid values are `rou_asset|lease_liability|lease_expense|not_applicable`',
    `line_item_display` BOOLEAN COMMENT 'Indicates whether individual line items posted to this account are stored and displayable (True) in the FI line item report. Required for accounts needing detailed transaction-level audit trails. Maps to SAP field XKRES in SKB1.',
    `open_item_management` BOOLEAN COMMENT 'Indicates whether open item management is active (True) for this account, enabling individual line items to be matched and cleared (e.g., for clearing accounts, GR/IR accounts, bank clearing). Maps to SAP field XOPVW in SKB1.',
    `planning_relevant` BOOLEAN COMMENT 'Indicates whether this GL account is included in financial planning and budgeting processes (True). Planning-relevant accounts are available for budget entry in SAP BPC or S/4HANA Financial Planning, supporting annual budgeting and rolling forecast cycles.',
    `posting_blocked` BOOLEAN COMMENT 'Indicates whether financial postings to this GL account are currently blocked (True) or permitted (False). A blocked account cannot receive new journal entries but retains its historical balance. Maps to SAP field XSPEB in SKA1/SKB1.',
    `profit_center_relevant` BOOLEAN COMMENT 'Indicates whether postings to this GL account are distributed to profit centers (True) for segment and store-level P&L reporting. Profit center-relevant accounts enable comparable store sales (Comp Sales/SSS) analysis and GMROI reporting by retail location.',
    `profit_loss_category` STRING COMMENT 'Business classification of the GL account within the P&L statement structure. Enables EBITDA tracking, gross margin analysis, and COGS reporting. revenue includes net sales and other income; cogs covers Cost of Goods Sold; gross_margin is a subtotal indicator; operating_expense covers SG&A and store operations; ebitda marks EBITDA-relevant accounts. [ENUM-REF-CANDIDATE: revenue|cogs|gross_margin|operating_expense|ebitda|depreciation|interest|tax|not_applicable — promote to reference product]',
    `reconciliation_account_type` STRING COMMENT 'Identifies whether this GL account serves as a reconciliation (control) account for a subledger. customer links to accounts receivable subledger; vendor links to accounts payable subledger; asset links to fixed asset subledger; none indicates a standalone GL account. Maps to SAP field MITKZ in SKB1.. Valid values are `customer|vendor|asset|none`',
    `revenue_recognition_method` STRING COMMENT 'Specifies the ASC 606 revenue recognition pattern applicable to this revenue GL account. point_in_time applies to standard retail POS and e-commerce sales; over_time applies to gift card breakage, loyalty program deferrals, and subscription revenues; not_applicable for non-revenue accounts. Drives automated revenue recognition scheduling in SAP FI.. Valid values are `point_in_time|over_time|not_applicable`',
    `sort_key` STRING COMMENT 'Three-digit SAP sort key that determines which document field is used to populate the allocation field in line items posted to this account (e.g., 001 = posting date, 012 = document number). Drives line item sorting in account statements and aging reports.. Valid values are `^[0-9]{3}$`',
    `source_system_code` STRING COMMENT 'Identifier of the operational source system from which this GL account master record was ingested (e.g., SAP_S4HANA_PROD, SAP_S4HANA_QA). Supports multi-system data lineage and Informatica MDM golden record traceability.',
    `statistical_account` BOOLEAN COMMENT 'Indicates whether this is a statistical GL account (True) used for management reporting and KPI tracking without affecting the legal financial statements. Statistical accounts capture quantities or values for internal analytics such as footfall, units sold, or headcount.',
    `tax_category` STRING COMMENT 'Defines the tax relevance of the GL account for input/output tax determination. Controls whether tax codes are required, optional, or not applicable during posting. Maps to SAP field MWSKZ in SKB1. [ENUM-REF-CANDIDATE: input_tax|output_tax|not_relevant|tax_only|deferred_tax|use_tax — promote to reference product]',
    `tax_posting_required` BOOLEAN COMMENT 'Indicates whether a tax code is mandatory (True) when posting to this GL account. Enforces tax compliance controls at the point of financial entry, ensuring all taxable transactions are properly coded for regulatory reporting.',
    `tolerance_group` STRING COMMENT 'SAP tolerance group assigned to this GL account that defines acceptable variance thresholds for payment differences, rounding, and clearing. Controls automatic clearing of small differences during accounts payable and receivable processing.',
    CONSTRAINT pk_gl_account PRIMARY KEY(`gl_account_id`)
) COMMENT 'General ledger chart of accounts master data aligned to SAP S/4HANA FI-GL. Defines every account used in financial postings including P&L accounts (revenue, COGS, operating expenses), balance sheet accounts (assets, liabilities, equity), and statistical accounts. Includes account type, financial statement version assignment, tax category, and FASB/GAAP classification.';

CREATE OR REPLACE TABLE `retail_ecm`.`finance`.`journal_entry` (
    `journal_entry_id` BIGINT COMMENT 'Unique surrogate identifier for each journal entry record in the general ledger. Primary key for the journal_entry data product in the Databricks Silver Layer.',
    `cost_center_id` BIGINT COMMENT 'Reference to the SAP CO cost center to which the journal entry is assigned for management accounting and internal P&L reporting. Enables cost allocation across store operations, distribution centers, and corporate functions.',
    `financial_period_id` BIGINT COMMENT 'Foreign key linking to finance.financial_period. Business justification: Journal entries are posted to specific fiscal periods. The journal_entry table has fiscal_year (INT) and fiscal_period (INT) but no FK to financial_period master. This FK enables joining to get period',
    `gl_account_id` BIGINT COMMENT 'Reference to the primary General Ledger account associated with this journal entry header. In SAP FI-GL, the header-level GL account is used for document-level classification and routing. Supports P&L, balance sheet, and EBITDA reporting.',
    `ledger_id` BIGINT COMMENT 'SAP S/4HANA ledger identifier specifying which accounting ledger the entry is posted to (e.g., 0L = Leading Ledger for GAAP/FASB, N1 = Non-Leading Ledger for IFRS parallel accounting). Supports multi-GAAP reporting requirements.',
    `location_id` BIGINT COMMENT 'Reference to the SAP plant (store, distribution center, or warehouse) associated with this journal entry. Links financial postings to physical retail locations for store-level P&L, COGS, and inventory accounting (e.g., COGS postings from goods issue, DSD receipts).',
    `profit_center_id` BIGINT COMMENT 'Reference to the SAP CO profit center for segment-level P&L reporting. Enables gross margin, EBITDA, and revenue tracking by business unit, store, or product category in retail financial reporting.',
    `accrual_indicator` BOOLEAN COMMENT 'Flag indicating whether this journal entry represents an accrual posting (True) — i.e., an expense or revenue recognized in the current period but not yet cash-settled. Supports accrual accounting under FASB ASC 606 and period-end close processes.',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the journal entry was approved for posting in SAP S/4HANA FI-GL. Distinct from entry_timestamp (creation) and posting_date (ledger date). Supports SOX audit trail and financial close process monitoring.',
    `approved_by` STRING COMMENT 'SAP user ID of the approver who authorized the journal entry posting, particularly for parked documents and manual adjustments. Supports dual-control requirements under SOX Section 302/404 and internal audit controls.',
    `assignment_number` STRING COMMENT 'SAP FI assignment field (ZUONR) used for sorting and matching open items in accounts payable and receivable clearing. Typically populated with the purchase order number, sales order number, or payment reference for automated clearing and reconciliation.',
    `business_area` STRING COMMENT 'SAP FI business area code representing an organizational unit for which an internal balance sheet and P&L can be created. Used in retail for segment reporting across hypermarkets, department stores, discount outlets, and e-commerce channels.. Valid values are `^[A-Z0-9]{4}$`',
    `company_code` STRING COMMENT 'SAP S/4HANA four-character company code identifying the legal entity or organizational unit for which the journal entry is posted. Aligns with the FI-GL company code configuration and supports intercompany elimination and entity-level P&L reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `debit_credit_indicator` STRING COMMENT 'Indicates whether the journal entry header represents a debit (D) or credit (C) posting at the document level. Fundamental double-entry bookkeeping indicator used in SAP FI-GL for balance validation and financial statement preparation.. Valid values are `D|C`',
    `deferred_revenue_indicator` BOOLEAN COMMENT 'Flag indicating whether this journal entry records deferred revenue (True) — i.e., cash received but revenue not yet recognized per FASB ASC 606 performance obligation criteria. Relevant for gift cards, loyalty points, subscription services, and BOPIS/ROPIS prepayments in retail.',
    `document_amount` DECIMAL(18,2) COMMENT 'Gross total amount of the journal entry in the document (transaction) currency. Represents the sum of all debit or credit line items before netting. Used for financial reporting, reconciliation, and audit trail in retail P&L and balance sheet analysis.',
    `document_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code of the transaction currency in which the journal entry amounts are originally recorded (e.g., USD, EUR, GBP). Distinct from local/company code currency. Required for multi-currency retail operations and FX reporting.. Valid values are `^[A-Z]{3}$`',
    `document_date` DATE COMMENT 'The date of the original source document (invoice, receipt, contract, etc.) that triggered the journal entry. May differ from the posting date and is used for aging analysis, vendor/customer reconciliation, and audit trail purposes.',
    `document_number` STRING COMMENT 'SAP FI accounting document number uniquely identifying the journal entry within a company code and fiscal year. This is the externally-known business identifier used in audit trails, reconciliation, and cross-system references (e.g., EDI, ERP).. Valid values are `^[0-9]{10}$`',
    `document_type` STRING COMMENT 'SAP FI two-character document type code classifying the nature of the accounting document (e.g., SA=General Ledger, KR=Vendor Invoice, DR=Customer Invoice, AA=Asset Posting, AB=Accounting Document, ZP=Payment Clearing, RV=Revenue). Drives number range assignment and account type determination. [ENUM-REF-CANDIDATE: SA|KR|DR|AA|AB|ZP|RV|KZ|DZ|WA|WE|RE — promote to reference product]. Valid values are `^[A-Z0-9]{2}$`',
    `entered_by` STRING COMMENT 'SAP user ID of the person or system process that created the journal entry in SAP S/4HANA FI-GL. Required for FASB-compliant audit trail, SOX internal controls, and financial close accountability.',
    `entry_timestamp` TIMESTAMP COMMENT 'The exact date and time when the journal entry record was first created and saved in SAP S/4HANA FI-GL. Serves as the RECORD_AUDIT_CREATED timestamp for audit trail and FASB-compliant financial close documentation.',
    `entry_type` STRING COMMENT 'Classification of the journal entry by its accounting purpose: standard = normal business transaction; accrual = expense/revenue accrual; reversal = reversal of a prior entry; adjustment = period-end correction; intercompany = elimination entry; depreciation = fixed asset depreciation; lease = ASC 842 lease expense; reclassification = account reclassification. [ENUM-REF-CANDIDATE: standard|accrual|reversal|adjustment|intercompany|depreciation|lease|reclassification|deferred_revenue|cogs — promote to reference product]',
    `fiscal_period` STRING COMMENT 'The accounting period (1–16 in SAP, including special periods 13–16 for year-end adjustments) within the fiscal year in which the journal entry is posted. Critical for period-end close, accrual management, and financial reporting cycles.',
    `fiscal_year` STRING COMMENT 'The fiscal year in which the journal entry is recorded (e.g., 2024). Used for period-end financial close, P&L reporting, and EBITDA tracking aligned with the retail fiscal calendar.',
    `functional_area` STRING COMMENT 'SAP FI functional area code classifying the journal entry by business function for cost-of-sales P&L reporting (e.g., COGS, Selling, Administration, Distribution, Marketing). Supports income statement presentation under FASB ASC 606.',
    `fx_rate` DECIMAL(18,2) COMMENT 'Exchange rate applied to translate document currency amounts to local currency at the time of posting. Sourced from SAP FI exchange rate tables. Critical for multi-currency retail operations, FX gain/loss accounting, and FASB ASC 830 compliance.',
    `header_text` STRING COMMENT 'Free-text description or business justification entered at the journal entry header level in SAP FI-GL. Provides context for the posting (e.g., Q3 Rent Accrual, COGS Adjustment - Store 1042, Intercompany Elimination - FY2024 Q4). Required for audit trail and financial close documentation.',
    `intercompany_indicator` BOOLEAN COMMENT 'Flag indicating whether this journal entry involves a transaction between two legal entities within the same corporate group (True). Used for intercompany elimination in consolidated financial statements under FASB ASC 810.',
    `last_changed_timestamp` TIMESTAMP COMMENT 'The date and time when the journal entry record was last modified in SAP S/4HANA FI-GL. Supports audit trail requirements, change tracking, and financial close process monitoring.',
    `local_amount` DECIMAL(18,2) COMMENT 'Total amount of the journal entry translated into the company codes local (functional) currency using the FX rate at posting date. Used for statutory P&L, balance sheet, and EBITDA reporting under FASB standards.',
    `local_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code of the company codes local (functional) currency. Used for statutory reporting and local GAAP compliance. Amounts are translated from document currency to local currency using the FX rate.. Valid values are `^[A-Z]{3}$`',
    `posting_date` DATE COMMENT 'The date on which the journal entry is posted to the general ledger and determines the fiscal period assignment. Distinct from the document date and entry date. Governs period-end P&L, balance sheet, and EBITDA reporting.',
    `posting_key` STRING COMMENT 'SAP FI two-digit posting key controlling the debit/credit assignment, account type, and field selection for the journal entry (e.g., 40=Debit G/L, 50=Credit G/L, 01=Customer Invoice, 31=Vendor Invoice). Fundamental SAP FI-GL configuration element.. Valid values are `^[0-9]{2}$`',
    `posting_status` STRING COMMENT 'Current lifecycle state of the journal entry in the SAP FI-GL workflow. draft = entry in preparation; posted = fully posted to ledger; parked = saved but not yet posted (pending approval); held = temporarily saved; reversed = entry has been reversed; error = posting failed validation.. Valid values are `draft|posted|parked|held|reversed|error`',
    `reference_document_number` STRING COMMENT 'External or cross-system reference document number associated with the journal entry (e.g., vendor invoice number, purchase order number, sales order number, EDI transaction reference). Enables cross-module and cross-system reconciliation in SAP FI-GL.',
    `reversal_indicator` BOOLEAN COMMENT 'Flag indicating whether this journal entry is a reversal of a previously posted document (True) or an original posting (False). Used in SAP FI-GL for accrual reversal management and period-end close processes.',
    `reversed_document_number` STRING COMMENT 'The SAP accounting document number of the original entry that this journal entry reverses. Populated only when reversal_indicator is True. Provides the audit trail link between reversal and original posting for FASB-compliant financial close.',
    `scheduled_reversal_date` DATE COMMENT 'The date on which SAP S/4HANA is scheduled to automatically reverse this journal entry (typically the first day of the following period for accrual entries). Populated when accrual_indicator is True. Supports automated period-end close and accrual management.',
    `segment_code` STRING COMMENT 'SAP S/4HANA segment identifier for FASB ASC 280 segment reporting. Classifies the journal entry by reportable business segment (e.g., Grocery, Apparel, Electronics, E-Commerce, Private Label). Enables segment-level P&L and EBITDA disclosure.',
    `source_module` STRING COMMENT 'SAP S/4HANA module that originated the journal entry posting (e.g., FI-AP=Accounts Payable, FI-AR=Accounts Receivable, FI-AA=Asset Accounting, FI-TX=Tax Accounting, MM=Materials Management, SD=Sales & Distribution, CO=Controlling). Enables source-system traceability and cross-module reconciliation. [ENUM-REF-CANDIDATE: FI-AP|FI-AR|FI-AA|FI-TX|FI-GL|MM|SD|CO|PP|WM — 10 candidates stripped; promote to reference product]',
    `tax_amount` DECIMAL(18,2) COMMENT 'Tax amount (sales tax, VAT, or use tax) included in or associated with the journal entry in document currency. Relevant for FI-TX (Tax Accounting) postings and compliance with FTC pricing transparency and FDA labeling requirements for grocery retail.',
    `trading_partner_code` STRING COMMENT 'SAP company code of the intercompany trading partner involved in this journal entry. Populated only when intercompany_indicator is True. Required for intercompany reconciliation and elimination in consolidated P&L and balance sheet reporting.. Valid values are `^[A-Z0-9]{4}$`',
    CONSTRAINT pk_journal_entry PRIMARY KEY(`journal_entry_id`)
) COMMENT 'Core general ledger journal entry header capturing all financial postings in SAP S/4HANA FI-GL, including accrual entries, scheduled reversals, and period-end closing entries. Records accounting documents for sales revenue, COGS, expense accruals, revenue accruals, deferred revenue, adjustments, intercompany eliminations, depreciation, lease expense, and reclassifications. Includes document type, posting date, fiscal period, company code, document/local currency, FX rate, reference document, posting status, accrual/reversal indicators, source module (FI-AP, FI-AR, FI-AA, FI-TX), and business justification. FASB-compliant audit trail for all financial transactions supporting accurate period-end P&L, balance sheet, and EBITDA reporting.';

CREATE OR REPLACE TABLE `retail_ecm`.`finance`.`journal_entry_line` (
    `journal_entry_line_id` BIGINT COMMENT 'Unique surrogate identifier for each journal entry line item in the general ledger. Primary key for this silver-layer data product, aligned to SAP FI-GL line item table (BSEG).',
    `cost_center_id` BIGINT COMMENT 'Reference to the cost center responsible for this line item posting, corresponding to SAP BSEG-KOSTL. Enables cost allocation and departmental P&L reporting.',
    `gl_account_id` BIGINT COMMENT 'Reference to the GL account to which this line item is posted, corresponding to SAP BSEG-HKONT. Drives P&L, balance sheet, and EBITDA reporting.',
    `journal_entry_id` BIGINT COMMENT 'Reference to the parent journal entry header (BKPF in SAP FI) to which this line item belongs. Enables drill-down from financial statements to individual debit/credit postings.',
    `order_line_id` BIGINT COMMENT 'Foreign key linking to order.order_line. Business justification: COGS and revenue drill-through: retail finance analysts trace journal entry lines (revenue, COGS, discount expense) back to originating order lines for margin analysis, revenue recognition audit, and ',
    `po_line_id` BIGINT COMMENT 'Foreign key linking to supplychain.po_line. Business justification: Retail accounting posts accruals, COGS, and GR/IR clearing at the PO line level. The existing journal_entry_line→purchase_order FK is header-level only. Line-level linkage enables granular SKU/cost-ce',
    `pos_transaction_line_id` BIGINT COMMENT 'Foreign key linking to order.pos_transaction_line. Business justification: Store-level GL reconciliation: POS transaction lines drive revenue and COGS journal entries. Retail store controllers trace journal entry lines to POS transaction lines for daily close reconciliation,',
    `profit_center_id` BIGINT COMMENT 'Reference to the profit center associated with this line item, corresponding to SAP BSEG-PRCTR. Supports segment-level P&L and EBITDA reporting by business unit or store.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to supplychain.purchase_order. Business justification: Line-level detail for PO-related postings including freight charges, import duties, and purchase price variances. Supports detailed cost accounting and variance analysis required in retail operations.',
    `account_type` STRING COMMENT 'SAP account type indicator (KOART): A=Asset, D=Customer (Debtor), K=Vendor (Creditor), M=Material, S=GL Account. Determines the sub-ledger reconciliation account and financial statement classification.. Valid values are `A|D|K|M|S`',
    `amount_doc_currency` DECIMAL(18,2) COMMENT 'The transaction amount in the document (transaction) currency, corresponding to SAP BSEG-WRBTR. Used for multi-currency financial reporting and foreign exchange analysis.',
    `amount_group_currency` DECIMAL(18,2) COMMENT 'The transaction amount translated to the group (consolidation) currency, corresponding to SAP BSEG-KURSF-derived group currency amount. Supports consolidated P&L and EBITDA reporting across all legal entities.',
    `amount_local_currency` DECIMAL(18,2) COMMENT 'The transaction amount translated to the company code local currency, corresponding to SAP BSEG-DMBTR. Used for statutory financial reporting and local GAAP compliance.',
    `assignment` STRING COMMENT 'Free-form assignment field used for line item sorting and allocation, corresponding to SAP BSEG-ZUONR. Typically populated with a reference number (e.g., purchase order, cost object) to facilitate reconciliation and reporting.',
    `business_area` STRING COMMENT 'SAP business area code (GSBER) representing an organizational unit for which an internal balance sheet and P&L can be created. Used for segment reporting across store formats (hypermarket, e-commerce, discount).. Valid values are `^[A-Z0-9]{4}$`',
    `clearing_date` DATE COMMENT 'The date on which this open item was cleared (AUGDT in SAP BSEG). Null for uncleared items. Used for days-payable-outstanding (DPO) and days-sales-outstanding (DSO) calculations.',
    `clearing_document_number` STRING COMMENT 'SAP clearing document number (AUGBL) assigned when this open item is cleared against a payment or offsetting entry. Null for uncleared items. Used in accounts payable/receivable reconciliation and aging analysis.',
    `company_code` STRING COMMENT 'SAP company code (BUKRS) representing the legal entity for which this journal entry line is posted. Enables multi-entity financial consolidation and statutory reporting.. Valid values are `^[A-Z0-9]{4}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this journal entry line record was first created in the system, corresponding to SAP BKPF-CPUDT and CPUTM combined. Used for audit trail, financial close monitoring, and SOX compliance.',
    `debit_credit_indicator` STRING COMMENT 'Indicates whether this line item is a debit (D) or credit (C) posting, corresponding to SAP BSEG-SHKZG. Fundamental to double-entry bookkeeping and trial balance validation.. Valid values are `D|C`',
    `doc_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the document (transaction) currency, corresponding to SAP BSEG-WAERS. Enables multi-currency P&L and balance sheet reporting.. Valid values are `^[A-Z]{3}$`',
    `document_date` DATE COMMENT 'The date of the originating source document (invoice, receipt, etc.), corresponding to SAP BSEG-BLDAT. May differ from posting date; used for accrual and cutoff analysis.',
    `document_type` STRING COMMENT 'SAP document type code (e.g., SA=GL posting, KR=vendor invoice, DR=customer invoice, AB=accounting document), corresponding to SAP BKPF-BLART. Classifies the nature of the journal entry for reporting and audit. [ENUM-REF-CANDIDATE: SA|KR|DR|AB|KZ|DZ|WA|WE|RE|RV — promote to reference product]',
    `exchange_rate` DECIMAL(18,2) COMMENT 'The foreign currency exchange rate applied to translate the document currency amount to local currency, corresponding to SAP BSEG-KURSF. Used for FX gain/loss analysis and multi-currency reconciliation.',
    `fiscal_period` STRING COMMENT 'Fiscal posting period (1–16, including special periods) within the fiscal year, corresponding to SAP BSEG-MONAT. Drives monthly financial close and period-end reporting.',
    `fiscal_year` STRING COMMENT 'Fiscal year in which this journal entry line is posted, corresponding to SAP BSEG-GJAHR. Used for annual financial close, budgeting, and year-over-year P&L comparisons.',
    `functional_area` STRING COMMENT 'SAP functional area (FKBER) used for cost-of-sales accounting, classifying expenses by business function (e.g., COGS, selling, administration, distribution). Supports P&L by function reporting.',
    `internal_order_number` BIGINT COMMENT 'Reference to the SAP internal order (AUFNR) to which this line item is assigned. Used for project-level cost tracking, capital expenditure monitoring, and marketing campaign cost allocation.',
    `is_reversed` BOOLEAN COMMENT 'Indicates whether this journal entry line has been reversed (True) or is active (False), derived from SAP BKPF-STBLG. Reversed entries must be excluded from financial statement totals to prevent double-counting.',
    `ledger_group` STRING COMMENT 'SAP ledger group (LDGRP) identifying the accounting principle under which this line is posted (e.g., leading ledger for GAAP, non-leading ledger for IFRS). Supports parallel accounting for multi-GAAP reporting.',
    `line_item_text` STRING COMMENT 'Descriptive text for this journal entry line item, corresponding to SAP BSEG-SGTXT. Provides narrative context for auditors, financial analysts, and during financial close review.',
    `line_number` STRING COMMENT 'Sequential line item number within the parent journal entry, corresponding to SAP BSEG-BUZEI. Used to order and uniquely identify each debit or credit posting within a document.',
    `local_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the company code local currency, corresponding to SAP BSEG-PSWSL. Required for statutory reporting and local GAAP financial statements.. Valid values are `^[A-Z]{3}$`',
    `material_number` STRING COMMENT 'SAP material number (MATNR in BSEG) corresponding to the Stock Keeping Unit (SKU) associated with this line item. Populated for inventory valuation, COGS, and goods movement postings. Enables drill-down from GL to product-level cost analysis.',
    `posting_date` DATE COMMENT 'The date on which this line item is posted to the general ledger, corresponding to SAP BSEG-BUDAT. Determines the fiscal period and year for financial reporting.',
    `posting_key` STRING COMMENT 'Two-digit SAP posting key (BSCHL) that determines the account type, debit/credit indicator, and field selection for this line item. Examples: 40=GL debit, 50=GL credit, 31=vendor credit, 01=customer debit.. Valid values are `^[0-9]{2}$`',
    `quantity` DECIMAL(18,2) COMMENT 'The quantity associated with this line item (MENGE in SAP BSEG), applicable for material-related postings such as goods receipts, inventory adjustments, and COGS entries. Enables unit-level cost analysis.',
    `reference_document_number` STRING COMMENT 'External reference document number (XBLNR from BKPF) such as a vendor invoice number, purchase order number, or customer order number. Enables cross-system reconciliation between ERP and source operational systems.',
    `reversal_document_number` STRING COMMENT 'The SAP document number of the reversing entry (STBLG from BKPF), if this line has been reversed. Enables audit trail tracing from original posting to reversal for financial close and SOX compliance.',
    `special_gl_indicator` STRING COMMENT 'SAP special GL indicator (UMSKZ) used for down payments, guarantees, and other special transactions that are posted to alternative reconciliation accounts. Blank for standard postings.. Valid values are `^[A-Z0-9]?$`',
    `tax_amount` DECIMAL(18,2) COMMENT 'The tax amount (VAT/sales tax) associated with this line item in document currency, corresponding to SAP BSEG-WMWST. Required for tax compliance reporting and accounts payable/receivable reconciliation.',
    `tax_code` STRING COMMENT 'Tax code assigned to this line item for VAT/sales tax determination, corresponding to SAP BSEG-MWSKZ. Drives tax reporting, compliance, and accounts payable/receivable tax calculations.. Valid values are `^[A-Z0-9]{2}$`',
    `unit_of_measure` STRING COMMENT 'Unit of measure for the quantity field (MEINS in SAP BSEG), such as EA (each), KG (kilogram), or CS (case). Required for material-related GL postings to support COGS and inventory valuation analysis.. Valid values are `^[A-Z]{2,3}$`',
    `value_date` DATE COMMENT 'The effective date for cash flow and bank reconciliation purposes, corresponding to SAP BSEG-VALUT. Used in treasury and accounts payable/receivable aging analysis.',
    `wbs_element` STRING COMMENT 'SAP WBS element (PROJK) for project-based cost assignment, corresponding to capital expenditure projects such as store openings, DC expansions, or IT implementations. Supports CAPEX tracking and ASC 842 lease accounting.',
    CONSTRAINT pk_journal_entry_line PRIMARY KEY(`journal_entry_line_id`)
) COMMENT 'Line-item detail for each general ledger journal entry, representing individual debit and credit postings to GL accounts. Captures GL account, cost center, profit center, amount in document and local currency, tax code, assignment field, and line item text. Enables drill-down from financial statements to source transactions. Aligns to SAP FI-GL line item table (BSEG).';

CREATE OR REPLACE TABLE `retail_ecm`.`finance`.`ap_invoice` (
    `ap_invoice_id` BIGINT COMMENT 'Unique surrogate primary key for the AP invoice record in the Databricks Silver Layer lakehouse. Assigned by the data platform upon ingestion from SAP S/4HANA FI-AP.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: AP invoices have cost_center_code (STRING) but no FK to cost_center master. This FK enables cost allocation and reporting. The cost_center table is the SSOT for cost center master data in SAP S/4HANA ',
    `financial_period_id` BIGINT COMMENT 'Foreign key linking to finance.financial_period. Business justification: AP invoices are posted to fiscal periods. The ap_invoice table has fiscal_year (STRING) and fiscal_period (STRING) but no FK to the financial_period master. This FK enables period-level controls (post',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: AP invoices have gl_account_code (STRING) but no FK to gl_account master. This FK enables account validation, financial statement mapping, and ensures postings use valid GL accounts from the chart of ',
    `inbound_shipment_id` BIGINT COMMENT 'Foreign key linking to supplychain.inbound_shipment. Business justification: Freight and logistics invoices reference specific inbound shipments for accrual matching, payment processing, and freight cost allocation. Standard AP three-way match process in retail supply chain.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: In SAP S/4HANA FI, every AP invoice posting generates a corresponding GL journal entry (FI document). Linking ap_invoice.journal_entry_id → journal_entry.journal_entry_id establishes the direct sub-le',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: AP invoices in SAP S/4HANA post to a specific ledger (leading ledger for statutory reporting, extension ledgers for IFRS or management accounting). Linking ap_invoice.ledger_id → ledger.ledger_id enab',
    `location_id` BIGINT COMMENT 'Foreign key linking to store.location. Business justification: AP invoices for store-specific vendor deliveries (DSD, store supplies, maintenance) must be attributed to the receiving store location for cost allocation and three-way match. Retail AP teams process ',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: AP invoices have profit_center_code (STRING) but no FK to profit_center master. This FK enables P&L allocation and profit center reporting.',
    `purchase_order_id` BIGINT COMMENT 'Reference to the purchase order against which this invoice is matched during three-way match (PO/GR/Invoice) processing in SAP S/4HANA MM.',
    `receiving_event_id` BIGINT COMMENT 'Foreign key linking to supplychain.receiving_event. Business justification: Retail AP 3-way match (PO + goods receipt + invoice) requires linking ap_invoice directly to the receiving_event that confirmed physical receipt. goods_receipt_number on ap_invoice is a denormalized r',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to supplier.vendor_contract. Business justification: Retail AP three-way match requires invoices to be validated against the governing vendor contract for payment terms, discount eligibility, and compliance. Finance teams link invoices to contracts for ',
    `vendor_id` BIGINT COMMENT 'Reference to the vendor (supplier) master record who issued this invoice. Links to the supplier/vendor master in SAP S/4HANA MM and Informatica MDM golden record.',
    `chargeback_amount` DECIMAL(18,2) COMMENT 'Amount deducted from the invoice payment as a vendor compliance penalty (chargeback) for violations such as late delivery, labeling errors, or EDI non-compliance. Reduces net payment to vendor.',
    `clearing_date` DATE COMMENT 'Date on which the open AP invoice item was cleared (settled) in the SAP FI-AP subledger, either by payment, credit memo offset, or manual clearing. Marks the end of the invoice lifecycle.',
    `clearing_document_number` STRING COMMENT 'SAP FI document number of the clearing transaction (AUGBL) that settled this invoice item. Enables full audit trail from invoice receipt through payment clearing for SOX compliance.',
    `company_code` STRING COMMENT 'SAP company code (BUKRS) representing the legal entity or organizational unit responsible for this AP invoice. Determines the chart of accounts, fiscal year variant, and currency for financial reporting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the AP invoice record was first created in the source system (SAP S/4HANA FI-AP) or ingested into the Databricks Silver Layer. Supports audit trail and data lineage for period-end close.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the invoice is denominated (e.g., USD, EUR, GBP). Required for multi-currency AP processing and foreign exchange revaluation in SAP FI.. Valid values are `^[A-Z]{3}$`',
    `discount_amount` DECIMAL(18,2) COMMENT 'Cash discount amount available if payment is made by the discount due date. Represents the financial benefit of early payment and is tracked for cash discount capture rate KPI reporting.',
    `discount_due_date` DATE COMMENT 'Last date by which payment must be made to capture the early payment cash discount offered by the vendor (e.g., 2/10 Net 30 — discount expires on day 10). Critical for cash discount capture optimization.',
    `dispute_reason` STRING COMMENT 'Reason code for invoices placed in disputed status during three-way match or AP review. Drives dispute resolution workflow and vendor communication in SAP FI-AP and Salesforce Service Cloud. [ENUM-REF-CANDIDATE: price_discrepancy|quantity_discrepancy|duplicate_invoice|missing_po|quality_issue|chargeback|other — promote to reference product]',
    `due_date` DATE COMMENT 'Calculated date by which payment must be made to the vendor to comply with agreed payment terms and avoid late payment penalties. Derived from invoice date plus payment terms net days in SAP FI-AP.',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Exchange rate applied to convert the invoice currency to the company code local currency at the time of posting. Used for foreign currency AP revaluation and P&L reporting.',
    `fiscal_period` STRING COMMENT 'SAP fiscal posting period (MONAT) within the fiscal year (01–12 for regular periods, 13–16 for special closing periods). Determines the accounting period for AP subledger and GL reconciliation.. Valid values are `^(0[1-9]|1[0-6])$`',
    `fiscal_year` STRING COMMENT 'SAP fiscal year (GJAHR) in which the invoice is posted. Used for period-end AP close, financial reporting, and year-over-year AP aging and spend analysis.. Valid values are `^[0-9]{4}$`',
    `gross_amount` DECIMAL(18,2) COMMENT 'Total gross invoice amount before any deductions, discounts, or tax adjustments as stated on the vendor invoice. Represents the full obligation prior to netting. Corresponds to WRBTR in SAP FI.',
    `invoice_date` DATE COMMENT 'Date printed on the vendor invoice document. Used as the baseline date for payment terms calculation (e.g., Net 30 from invoice date) and cash discount eligibility. Corresponds to BLDAT in SAP FI.',
    `invoice_number` STRING COMMENT 'Externally assigned invoice number as provided by the vendor on the invoice document. Used for vendor reconciliation, EDI matching, and dispute resolution. Corresponds to BELNR field in SAP FI-AP.',
    `invoice_status` STRING COMMENT 'Current workflow state of the AP invoice through the invoice-to-payment cycle. Drives AP aging analysis, payment run eligibility, and period-end close. [ENUM-REF-CANDIDATE: received|under_review|approved|posted|scheduled|paid|disputed|cancelled — promote to reference product]',
    `invoice_type` STRING COMMENT 'Classification of the invoice document type as defined in SAP FI-AP document type configuration. Determines posting logic, payment terms applicability, and GL account determination. [ENUM-REF-CANDIDATE: standard|credit_memo|debit_memo|recurring|intercompany|proforma — promote to reference product]. Valid values are `standard|credit_memo|debit_memo|recurring|intercompany|proforma`',
    `is_edi_received` BOOLEAN COMMENT 'Indicates whether the invoice was received electronically via EDI (Electronic Data Interchange) transmission from the vendor, as opposed to paper or email. EDI invoices (e.g., ANSI X12 810) enable straight-through processing.',
    `is_recurring` BOOLEAN COMMENT 'Indicates whether this invoice is part of a recurring payment schedule (e.g., monthly rent, lease payments under ASC 842, or standing service contracts). Recurring invoices are auto-generated in SAP FI-AP.',
    `net_amount` DECIMAL(18,2) COMMENT 'Net payable amount after applying all applicable discounts, deductions, and chargebacks. Represents the actual cash outflow obligation. Used for cash flow forecasting and AP aging analysis.',
    `payment_block` STRING COMMENT 'Indicator specifying whether and why the invoice is blocked from automatic payment processing. Corresponds to ZLSPR in SAP FI-AP. A value of none means the invoice is eligible for the next payment run.. Valid values are `none|manual_block|dispute_block|audit_block|duplicate_block`',
    `payment_date` DATE COMMENT 'Actual date on which payment was executed and disbursed to the vendor via the selected payment method (ACH, wire, check). Populated upon successful payment run completion in SAP FI-AP.',
    `payment_document_number` STRING COMMENT 'SAP FI document number generated for the payment transaction that clears this invoice. Used for bank reconciliation, remittance advice, and audit trail of the payment-to-invoice clearing.',
    `payment_method` STRING COMMENT 'Method by which the invoice will be or was settled (e.g., ACH electronic transfer, wire transfer, check, virtual card, EFT). Corresponds to ZLSCH in SAP FI-AP and determines payment run processing logic.. Valid values are `ACH|wire|check|virtual_card|EFT`',
    `payment_terms_code` STRING COMMENT 'SAP payment terms key (ZTERM) defining the agreed payment conditions with the vendor, including net days, discount percentages, and discount periods (e.g., ZB14 = 2% 10 days Net 30). Drives due date and discount date calculation.',
    `posting_date` DATE COMMENT 'Date on which the invoice was posted to the SAP general ledger and AP subledger. Determines the accounting period for financial reporting and period-end close. Corresponds to BUDAT in SAP FI.',
    `receipt_date` DATE COMMENT 'Date the vendor invoice was physically or electronically received by the AP department. Used to measure invoice processing cycle time and SLA compliance for vendor payment.',
    `remittance_reference` STRING COMMENT 'Reference number or text included in the payment remittance advice sent to the vendor, enabling the vendor to match the payment to their outstanding invoices. Supports vendor reconciliation and dispute prevention.',
    `sap_document_number` STRING COMMENT 'Internal SAP FI document number (BELNR) assigned upon posting of the invoice in SAP S/4HANA. Used for cross-reference with the general ledger and FI-AP subledger.',
    `tax_amount` DECIMAL(18,2) COMMENT 'Total tax amount (VAT, GST, sales tax) included in or applicable to the invoice as determined by SAP FI tax code configuration. Required for tax compliance reporting.',
    `three_way_match_status` STRING COMMENT 'Result of the three-way matching process comparing the purchase order (PO), goods receipt (GR), and vendor invoice quantities and amounts in SAP FI-AP/MM. Exceptions require AP team resolution before payment approval.. Valid values are `pending|matched|partial_match|exception|waived`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the AP invoice record, including status changes, payment updates, or dispute resolution actions. Supports change data capture (CDC) and audit compliance.',
    `vendor_bank_account` STRING COMMENT 'Masked or tokenized reference to the vendor bank account used for payment disbursement. Stored in compliance with PCI DSS requirements. Full account details are maintained in SAP FI-AP vendor master banking data.',
    CONSTRAINT pk_ap_invoice PRIMARY KEY(`ap_invoice_id`)
) COMMENT 'Accounts payable document lifecycle record capturing the full vendor invoice-to-payment cycle in SAP S/4HANA FI-AP. Encompasses invoice receipt, three-way match (PO/GR/Invoice), payment scheduling, payment execution (ACH, wire, check), discount capture, and settlement clearing. Includes vendor reference, purchase order linkage, payment terms, due dates, payment method, payment run details, bank account, remittance information, and clearing status. Supports vendor payment compliance, AP aging analysis, cash flow management, and period-end AP close.';

CREATE OR REPLACE TABLE `retail_ecm`.`finance`.`ar_invoice` (
    `ar_invoice_id` BIGINT COMMENT 'Unique surrogate primary key for the AR invoice record in the Databricks Silver Layer lakehouse. Entity role: TRANSACTION_HEADER.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: AR invoices in retail are billed against customer accounts for B2B credit terms, outstanding balance tracking, and AR aging reports. Account-level billing (tax-exempt status, credit limit) is distinct',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: AR invoices have cost_center_code (STRING) but no FK to cost_center master. This FK enables cost allocation for receivables.',
    `financial_period_id` BIGINT COMMENT 'Foreign key linking to finance.financial_period. Business justification: AR invoices are posted to fiscal periods. The ar_invoice table has fiscal_year (STRING) and fiscal_period (STRING) but no FK to financial_period master. This FK enables period controls and metadata. F',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: AR invoices have gl_account_code (STRING) but no FK to gl_account master. This FK enables account validation and financial statement mapping for receivables.',
    `header_id` BIGINT COMMENT 'Reference to the originating sales order that generated this invoice. Enables order-to-cash cycle tracing and revenue attribution back to the originating commercial transaction.',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: In SAP S/4HANA FI, every AR billing document generates a GL journal entry. Linking ar_invoice.journal_entry_id → journal_entry.journal_entry_id enables direct traceability from the AR sub-ledger to th',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: AR invoices in SAP S/4HANA post to a specific ledger for revenue recognition (ASC 606) and multi-GAAP reporting. Linking ar_invoice.ledger_id → ledger.ledger_id enables proper ledger-specific revenue ',
    `payment_method_id` BIGINT COMMENT 'Foreign key linking to customer.payment_method. Business justification: Retail AR invoice settlement requires linking to the payment method used for reconciliation, chargeback tracking, and payment processor reporting. Finance teams need to identify which card/wallet sett',
    `profile_id` BIGINT COMMENT 'Reference to the B2B customer (wholesale account, franchise, or commercial counterparty) to whom this invoice is issued. Satisfies TRANSACTION_HEADER PARTY_REFERENCE minimum category.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: AR invoices have profit_center_code (STRING) but no FK to profit_center master. This FK enables P&L allocation for revenue.',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to fulfillment.shipment. Business justification: ASC 606/IFRS 15 revenue recognition: retail recognizes revenue at point of control transfer (shipment). Finance runs shipped-not-invoiced reports and ties AR invoices directly to the triggering shipme',
    `subscription_id` BIGINT COMMENT 'Foreign key linking to order.subscription. Business justification: Subscription revenue recognition: recurring subscription billing generates periodic AR invoices. ASC 606 deferred revenue tracking and subscription lifecycle reporting require linking AR invoices to t',
    `applied_amount` DECIMAL(18,2) COMMENT 'Total amount of payments and credits applied against this invoice to date. Used to calculate the outstanding open balance and support partial payment tracking in cash application.',
    `bank_clearing_date` DATE COMMENT 'Date on which the payment was cleared through the bank and matched to this invoice in SAP FI-AR. Null until payment is received and cleared. Used for cash flow reporting and bank reconciliation.',
    `billing_category` STRING COMMENT 'Business category of the receivable indicating the commercial relationship type. Supports segmented AR reporting across wholesale accounts, franchise fee billing, commercial receivables, intercompany settlements, and drop-ship vendor billing.. Valid values are `wholesale|franchise_fee|commercial|intercompany|drop_ship`',
    `billing_document_number` STRING COMMENT 'Externally-known SAP FI-AR billing document number (BELNR) assigned at invoice creation. Used for customer remittance matching, EDI reconciliation, and dispute resolution. Satisfies TRANSACTION_HEADER BUSINESS_IDENTIFIER minimum category.. Valid values are `^[A-Z0-9]{1,20}$`',
    `cash_discount_amount` DECIMAL(18,2) COMMENT 'Early payment discount amount available to the customer if payment is received within the discount period defined in payment terms (e.g., 2% if paid within 10 days on 2/10NET30 terms).',
    `cash_discount_due_date` DATE COMMENT 'Last date by which the customer must pay to qualify for the early payment cash discount. Calculated from invoice_date and payment_terms_code discount period.',
    `clearing_document_number` STRING COMMENT 'SAP document number of the clearing transaction (payment, credit memo, or write-off) that fully or partially settled this invoice. Enables payment-to-invoice matching and audit trail.. Valid values are `^[A-Z0-9]{1,20}$`',
    `company_code` STRING COMMENT 'SAP company code (BUKRS) representing the legal entity issuing the invoice. Required for entity-level P&L, EBITDA reporting, and FASB-compliant financial close.. Valid values are `^[A-Z0-9]{1,6}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the AR invoice record was first created in the source system (SAP FI-AR). Used for audit trail and period-end close reconciliation. Satisfies TRANSACTION_HEADER RECORD_AUDIT_CREATED minimum category.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this invoice (e.g., USD, EUR, GBP). Required for multi-currency AR reporting and FX translation. Part of MONETARY_TRIPLET minimum category.. Valid values are `^[A-Z]{3}$`',
    `dispute_reason_code` STRING COMMENT 'Standardized SAP reason code for the customer dispute (e.g., pricing discrepancy, short shipment, quality issue, chargeback). Used for dispute root-cause analysis and vendor chargeback management.. Valid values are `^[A-Z0-9]{1,10}$`',
    `dispute_status` STRING COMMENT 'Current status of any customer dispute raised against this invoice. Drives collections workflow routing and dunning block management in SAP FI-AR and Salesforce Service Cloud.. Valid values are `none|open|under_review|resolved|escalated`',
    `due_date` DATE COMMENT 'Date by which full payment must be received per the agreed payment terms. Drives AR aging bucket classification (current, 1-30, 31-60, 61-90, 90+ days) and dunning trigger logic.',
    `dunning_block` BOOLEAN COMMENT 'Indicates whether dunning notices are blocked for this invoice (True = blocked). Set when a dispute is open, a payment arrangement is in place, or the account is under review.',
    `dunning_date` DATE COMMENT 'Date of the most recent dunning notice sent to the customer for this invoice. Used to track collections activity and enforce dunning interval rules.',
    `dunning_level` STRING COMMENT 'Current dunning escalation level (0–4) assigned to this invoice in SAP FI-AR dunning program. Level 0 = no dunning; higher levels indicate escalating collection notices sent to the customer.',
    `fiscal_period` STRING COMMENT 'Fiscal accounting period (01–12 for regular periods, 13–16 for special closing periods) within the fiscal year. Drives period-end AR close, aging bucket assignment, and monthly P&L reporting.. Valid values are `^(0[1-9]|1[0-6])$`',
    `fiscal_year` STRING COMMENT 'Fiscal year in which the invoice is posted (e.g., 2024). Used for annual P&L reporting, EBITDA tracking, and year-end AR close reconciliation.. Valid values are `^[0-9]{4}$`',
    `gross_amount` DECIMAL(18,2) COMMENT 'Total gross billed amount before tax, discounts, or adjustments. Represents the face value of goods or services invoiced to the B2B customer. Part of MONETARY_TRIPLET minimum category.',
    `invoice_date` DATE COMMENT 'The business date on which the invoice was issued to the customer. Represents the principal real-world event time for revenue recognition under ASC 606. Satisfies TRANSACTION_HEADER BUSINESS_EVENT_TIMESTAMP minimum category.',
    `invoice_status` STRING COMMENT 'Current lifecycle state of the AR invoice. Drives AR aging analysis, dunning workflow, and period-end close. Satisfies TRANSACTION_HEADER LIFECYCLE_STATUS minimum category.. Valid values are `open|partially_paid|paid|overdue|disputed|cancelled`',
    `invoice_type` STRING COMMENT 'Classification of the invoice document type in SAP FI-AR. Distinguishes standard customer invoices, credit memos for returns/adjustments, debit memos for chargebacks, proforma invoices, and intercompany billing.. Valid values are `standard|credit_memo|debit_memo|proforma|intercompany`',
    `net_amount` DECIMAL(18,2) COMMENT 'Net total amount due after applying discounts and before tax. Represents the contractual obligation for payment. Part of MONETARY_TRIPLET net total component.',
    `open_amount` DECIMAL(18,2) COMMENT 'Remaining unpaid balance on the invoice (net_amount minus applied_amount). Drives AR aging analysis, dunning escalation, and collections workflow prioritization.',
    `payment_block` BOOLEAN COMMENT 'Indicates whether the invoice is blocked from automatic payment processing (True = blocked). Applied during dispute resolution, credit hold, or compliance review.',
    `payment_method` STRING COMMENT 'Agreed payment instrument for settling this invoice (e.g., ACH bank transfer, wire, check). Determines cash application routing and bank clearing workflow in SAP FI-AR.. Valid values are `bank_transfer|check|ach|wire|credit_card|direct_debit`',
    `payment_terms_code` STRING COMMENT 'SAP payment terms key (e.g., NT30, NT60, 2/10NET30) defining the payment schedule, early payment discount percentage, and due date calculation rules for this invoice.. Valid values are `^[A-Z0-9]{1,10}$`',
    `posting_date` DATE COMMENT 'The accounting date on which the invoice is posted to the general ledger in SAP FI-AR. Determines the fiscal period for revenue recognition and AR balance reporting. May differ from invoice_date for period-end accruals.',
    `reference_document_number` STRING COMMENT 'External reference number provided by the customer (e.g., purchase order number, contract number) for remittance matching and EDI reconciliation. Stored in SAP FI-AR XBLNR field.. Valid values are `^[A-Z0-9]{1,20}$`',
    `revenue_recognition_date` DATE COMMENT 'Date on which revenue from this invoice was recognized under ASC 606 criteria (performance obligation satisfied). May differ from invoice_date for multi-element arrangements or deferred revenue scenarios.',
    `revenue_recognition_status` STRING COMMENT 'ASC 606 revenue recognition status for this invoice. Indicates whether revenue has been recognized, is deferred pending performance obligation fulfillment, or has been reversed. Critical for FASB-compliant financial reporting.. Valid values are `pending|recognized|deferred|reversed`',
    `sales_org_code` STRING COMMENT 'SAP sales organization (VKORG) responsible for this invoice. Enables P&L reporting and revenue attribution by sales channel, region, or business unit.. Valid values are `^[A-Z0-9]{1,10}$`',
    `tax_amount` DECIMAL(18,2) COMMENT 'Total tax amount applied to the invoice (sales tax, VAT, or applicable jurisdiction tax). Part of MONETARY_TRIPLET adjustment component.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the AR invoice record in the source system. Supports change data capture and audit compliance. Satisfies TRANSACTION_HEADER RECORD_AUDIT_UPDATED minimum category.',
    `write_off_amount` DECIMAL(18,2) COMMENT 'Amount written off as uncollectible bad debt for this invoice. Used for bad debt expense reporting, allowance for doubtful accounts calculation, and FASB-compliant AR reserve management.',
    `write_off_date` DATE COMMENT 'Date on which the invoice balance was written off as bad debt in SAP FI-AR. Null until a write-off is executed. Required for bad debt aging and allowance for doubtful accounts reporting.',
    CONSTRAINT pk_ar_invoice PRIMARY KEY(`ar_invoice_id`)
) COMMENT 'Accounts receivable document lifecycle record for B2B customer billing and cash collection in SAP S/4HANA FI-AR. Encompasses invoice creation, payment receipt, partial payment handling, cash discount processing, bank clearing, dunning activities, and collections management for wholesale accounts, franchise fees, and commercial receivables. Includes customer account, billing/due dates, payment terms, payment method, bank clearing date, applied amounts, dunning level, and ASC 606 revenue recognition flags. Supports AR aging analysis, cash application, collections workflow, and period-end AR close.';

CREATE OR REPLACE TABLE `retail_ecm`.`finance`.`budget` (
    `budget_id` BIGINT COMMENT 'Unique surrogate identifier for each budget record in the financial planning system. Primary key for the budget data product in SAP S/4HANA CO module.',
    `cost_center_id` BIGINT COMMENT 'Reference to the cost center or profit center responsible for this budget line. Aligns with SAP S/4HANA CO cost center master data for P&L and EBITDA reporting.',
    `dc_facility_id` BIGINT COMMENT 'Foreign key linking to supplychain.dc_facility. Business justification: DC operating budgets (labor, utilities, equipment) are planned and tracked by facility. Standard retail budgeting process requires facility-level budget allocation and variance reporting.',
    `financial_period_id` BIGINT COMMENT 'Foreign key linking to finance.financial_period. Business justification: Budget records are tied to specific fiscal periods. The budget table has fiscal_year (INT) and fiscal_period (INT) as separate columns, but no FK to the financial_period master. This FK enables joinin',
    `gl_account_id` BIGINT COMMENT 'Reference to the General Ledger (GL) account associated with this budget line item, enabling line-item granularity for financial reporting and FASB-compliant disclosures.',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: In SAP S/4HANA, budgets are defined within a specific ledger context (leading ledger for GAAP, extension ledgers for IFRS or management reporting). Linking finance_budget.ledger_id → ledger.ledger_id ',
    `location_id` BIGINT COMMENT 'Foreign key linking to store.location. Business justification: Store-level budgets must link directly to the store location for budget vs. actual variance reporting. Retail finance teams run store-level budget performance reports. finance_budget has cost_center_i',
    `profit_center_id` BIGINT COMMENT 'FK to finance.profit_center',
    `actual_amount` DECIMAL(18,2) COMMENT 'The actual financial amount posted to the GL account and cost center for this budget period. Sourced from SAP S/4HANA FI actuals for budget vs. actual variance analysis.',
    `approval_date` DATE COMMENT 'The date on which this budget record received final approval from the authorized approver. Required for audit trail and financial governance compliance.',
    `approval_status` STRING COMMENT 'Current workflow state of the budget record within the financial planning approval cycle. Tracks progression from draft through submission, review, approval, rejection, or period lock. [ENUM-REF-CANDIDATE: draft|submitted|under_review|approved|rejected|locked — promote to reference product]. Valid values are `draft|submitted|under_review|approved|rejected|locked`',
    `approved_by` STRING COMMENT 'The name or employee identifier of the financial authority (e.g., CFO, Finance Director, Cost Center Manager) who approved this budget record. Supports approval workflow audit trail.',
    `budget_category` STRING COMMENT 'High-level financial classification of the budget line: Capital Expenditure (CAPEX), Operating Expenditure (OPEX), Cost of Goods Sold (COGS), labor costs, or revenue. Drives P&L and EBITDA reporting segmentation.. Valid values are `CAPEX|OPEX|COGS|labor|revenue`',
    `budget_number` STRING COMMENT 'Externally-known alphanumeric identifier for the budget record, used in financial planning communications, approval workflows, and audit trails. Format: BDG-YYYY-NNNNNN.. Valid values are `^BDG-[0-9]{4}-[0-9]{6}$`',
    `channel` STRING COMMENT 'The retail channel (store, e-commerce, omnichannel, wholesale, marketplace) for which this budget is planned. Enables channel-level revenue, COGS, and gross margin projections.. Valid values are `store|ecommerce|omnichannel|wholesale|marketplace`',
    `cogs_projection` DECIMAL(18,2) COMMENT 'Planned Cost of Goods Sold (COGS) for the budget period, used to project gross margin and support merchandise planning and Open to Buy (OTB) calculations.',
    `committed_amount` DECIMAL(18,2) COMMENT 'The amount of the budget that has been formally committed through purchase orders or contracts but not yet expensed. Supports Open to Buy (OTB) integration and encumbrance accounting.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this budget record was first created in the financial planning system. Supports audit trail, data lineage, and financial close process tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts on this budget record (e.g., USD, EUR, GBP). Supports multi-currency financial planning and consolidation.. Valid values are `^[A-Z]{3}$`',
    `ebitda_projection` DECIMAL(18,2) COMMENT 'Planned Earnings Before Interest, Taxes, Depreciation, and Amortization (EBITDA) for the budget period. Key metric for investor financial guidance and enterprise P&L reporting.',
    `fiscal_period` STRING COMMENT 'The fiscal period (1–13, where 13 is a special closing period) within the fiscal year to which this budget line applies. Supports monthly and period-level budget vs. actual variance analysis in SAP CO.',
    `fiscal_quarter` STRING COMMENT 'The fiscal quarter (1–4) within the fiscal year for this budget record. Used for quarterly reforecast cycles, investor financial guidance, and quarterly P&L reporting.',
    `fiscal_year` STRING COMMENT 'The fiscal year (e.g., 2024) to which this budget record applies. Aligns with the retail fiscal calendar in SAP S/4HANA FI for annual financial planning and investor guidance.',
    `forecast_amount` DECIMAL(18,2) COMMENT 'The latest forward-looking financial estimate for this budget line, updated during rolling forecast or reforecast cycles. Used for forecast vs. prior forecast variance analysis and investor guidance.',
    `forecast_method` STRING COMMENT 'The methodology used to derive the forecast or budget amounts: top-down (executive-driven allocation), bottom-up (cost center aggregation), driver-based (KPI-linked), statistical (model-driven), or zero-based budgeting.. Valid values are `top_down|bottom_up|driver_based|statistical|zero_based`',
    `gross_margin_projection` DECIMAL(18,2) COMMENT 'Planned gross margin (revenue minus COGS) for the budget period and business unit. Supports Gross Margin Return on Investment (GMROI) analysis and financial close reporting.',
    `is_locked` BOOLEAN COMMENT 'Indicates whether this budget record has been locked for the period, preventing further edits. True when the period is closed or the budget has been formally locked post-approval.',
    `is_reforecast` BOOLEAN COMMENT 'Indicates whether this budget record represents a reforecast (True) rather than the original budget plan (False). Distinguishes reforecast iterations from baseline budget entries for variance tracking.',
    `lock_date` DATE COMMENT 'The date on which this budget record was locked to prevent further modifications, typically at period-end close. Supports financial close process integrity and audit compliance.',
    `notes` STRING COMMENT 'Free-text field for financial planners to document assumptions, rationale, or commentary associated with this budget record. Supports audit trail and management review during financial planning cycles.',
    `otb_amount` DECIMAL(18,2) COMMENT 'The Open to Buy (OTB) amount representing the remaining purchasing budget available for merchandise procurement in this period. Calculated as planned inventory budget minus committed and received inventory costs.',
    `plan_end_date` DATE COMMENT 'The end date of the planning period covered by this budget record. Defines the effective close of the budget window for financial reporting and period-end close processes.',
    `plan_start_date` DATE COMMENT 'The start date of the planning period covered by this budget record. Defines the effective beginning of the budget window for financial close and reporting alignment.',
    `plan_version_type` STRING COMMENT 'Classifies the budget record by planning cycle type: original budget (initial annual plan), revised budget (approved amendment), rolling forecast (monthly update), quarterly reforecast, or annual plan. Maps to SAP CO plan version category.. Valid values are `original_budget|revised_budget|rolling_forecast|quarterly_reforecast|annual_plan`',
    `planned_amount` DECIMAL(18,2) COMMENT 'The original planned financial amount for this budget line item in the functional currency. Represents the baseline against which actuals and forecasts are compared in budget vs. actual reporting.',
    `prior_forecast_amount` DECIMAL(18,2) COMMENT 'The forecast amount from the immediately preceding forecast cycle, retained for forecast vs. prior forecast variance analysis and trend tracking in financial planning.',
    `revenue_projection` DECIMAL(18,2) COMMENT 'Forward-looking revenue estimate for the business unit and channel in this budget period. Supports top-line financial planning, investor guidance, and Gross Merchandise Value (GMV) tracking.',
    `submission_date` DATE COMMENT 'The date on which this budget record was formally submitted for approval in the financial planning workflow. Supports submission tracking and planning cycle compliance.',
    `submitted_by` STRING COMMENT 'The name or employee identifier of the person who submitted this budget record for approval. Supports submission tracking and financial planning accountability.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to this budget record. Supports change tracking, audit trail, and incremental data loading in the Databricks Silver Layer.',
    `variance_amount` DECIMAL(18,2) COMMENT 'The absolute difference between planned amount and actual amount (actual_amount minus planned_amount) for this budget line. Positive value indicates overspend; negative indicates underspend. Supports budget vs. actual reporting.',
    `variance_pct` DECIMAL(18,2) COMMENT 'The percentage variance between planned and actual amounts ((actual - planned) / planned * 100). Used in financial dashboards and P&L reporting to flag material variances requiring management action.',
    CONSTRAINT pk_budget PRIMARY KEY(`budget_id`)
) COMMENT 'Comprehensive financial planning record encompassing annual budgets, periodic forecasts, rolling reforecasts, and forward-looking financial projections for retail business units, cost centers, and profit centers in SAP S/4HANA CO. Captures plan version (original budget, revised budget, monthly rolling forecast, quarterly reforecast, annual plan), fiscal year/period, category (CAPEX, OPEX, COGS, labor), GL account detail with line-item granularity (planned/committed/actual amounts per account and cost center), forecast method, variance analysis (budget vs. actual, forecast vs. prior forecast), revenue/COGS/gross margin/EBITDA projections by channel and business unit, approval workflow, and submission tracking. Supports OTB (Open to Buy) integration, budget vs. actual reporting, financial planning cycles, and investor financial guidance.';

CREATE OR REPLACE TABLE `retail_ecm`.`finance`.`financial_period` (
    `financial_period_id` BIGINT COMMENT 'Unique surrogate identifier for the financial period record in the retail fiscal calendar. Primary key for the financial_period data product.',
    `comparable_period_id` BIGINT COMMENT 'Reference to the corresponding financial period in the prior fiscal year used for same-store sales (SSS/Comp Sales) and year-over-year (YoY) financial comparisons. Accounts for 53-week year shifts in the NRF retail calendar.',
    `prior_year_period_financial_period_id` BIGINT COMMENT 'Reference to the exact same period number in the immediately preceding fiscal year. Used for year-over-year (YoY) financial variance analysis, P&L comparisons, and FASB comparative financial statement preparation. Distinct from comparable_period_id which accounts for 53-week calendar shifts.',
    `ap_posting_allowed` BOOLEAN COMMENT 'Indicates whether accounts payable (AP) postings are permitted for this financial period. AP periods may be managed independently from GL periods in SAP S/4HANA to support vendor invoice processing timelines and COGS accruals.',
    `ar_posting_allowed` BOOLEAN COMMENT 'Indicates whether accounts receivable (AR) postings are permitted for this financial period. AR periods may be managed independently to support customer payment processing, revenue recognition (ASC 606), and loyalty program financial settlements.',
    `budget_version` STRING COMMENT 'Identifier for the budget or plan version associated with this financial period (e.g., ORIGINAL, REVISED_Q2, FORECAST_V3). Links the period to the corresponding financial plan in SAP CO for budget vs. actual variance analysis and financial planning cycles.',
    `calendar_type` STRING COMMENT 'The retail fiscal calendar convention used for this period. The 4-5-4 and 4-4-5 calendars are NRF industry standards that divide the fiscal year into 4-week and 5-week periods to align comparable store sales (SSS) reporting across years.. Valid values are `4-5-4|4-4-5|4-5-4 Modified|Calendar Month|52-53 Week`',
    `close_cycle_days` STRING COMMENT 'Number of calendar days allocated for completing the financial close process for this period (from period end date to scheduled close date). A KPI for finance operations efficiency; industry benchmark for retail is typically 5–10 business days for month-end close.',
    `close_status` STRING COMMENT 'Status of the financial close process for this period. Tracks progression through the month-end or year-end close cycle. not_started indicates close activities have not begun; in_progress means close tasks are underway; completed means the period is fully closed and reconciled; reopened means a closed period was reopened for corrections.. Valid values are `not_started|in_progress|completed|reopened`',
    `company_code` STRING COMMENT 'SAP S/4HANA company code (Buchungskreis) to which this financial period configuration applies. A company code represents an independent legal entity within the retail enterprise (e.g., a specific banner, subsidiary, or country operation).',
    `controlling_area` STRING COMMENT 'SAP CO controlling area code associated with this financial period. The controlling area defines the organizational unit for cost accounting, P&L reporting, and EBITDA tracking within SAP S/4HANA CO module.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this financial period record was first created in the system. Supports audit trail requirements, data lineage tracking, and financial close governance per ISO 27001 and FASB standards.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the functional currency of the company code during this financial period (e.g., USD, EUR, GBP). Governs currency translation for consolidated P&L and EBITDA reporting.. Valid values are `^[A-Z]{3}$`',
    `end_date` DATE COMMENT 'The last calendar date of the financial period (inclusive). Defines the upper boundary for transaction posting, revenue recognition cutoff, and financial close. For 53-week fiscal years, the final period end date may extend one week beyond the standard calendar.',
    `fiscal_year` STRING COMMENT 'The retail fiscal year to which this period belongs (e.g., 2024). Retail fiscal years may not align with the calendar year; typically begins in late January or early February per the 4-5-4 or 4-4-5 retail calendar convention.',
    `fiscal_year_variant` STRING COMMENT 'SAP fiscal year variant code defining the fiscal year structure (e.g., K4 for calendar year, V3 for April–March, or a custom retail variant). Determines how posting periods map to calendar months in SAP S/4HANA FI/CO.',
    `gl_posting_allowed` BOOLEAN COMMENT 'Indicates whether general ledger (GL) journal entry postings are currently permitted for this financial period. Derived from posting_status but maintained as an explicit business flag for integration with downstream systems that check posting eligibility.',
    `is_53_week_year` BOOLEAN COMMENT 'Indicates whether the fiscal year containing this period is a 53-week year. Under the NRF 4-5-4 calendar, a 53rd week occurs approximately every 5–6 years to realign the fiscal calendar with the Gregorian calendar. Impacts comparable store sales (SSS) comparisons and year-over-year financial analysis.',
    `is_adjustment_period` BOOLEAN COMMENT 'Indicates whether this is a special adjustment period (periods 13–16 in SAP) used exclusively for year-end audit adjustments, accrual reversals, and FASB-required restatements. Adjustment periods do not correspond to calendar time.',
    `is_quarter_end_period` BOOLEAN COMMENT 'Indicates whether this period is the final period of a fiscal quarter, triggering quarterly close procedures, quarterly P&L reporting, and SEC 10-Q filing preparation for publicly traded retail entities.',
    `is_year_end_period` BOOLEAN COMMENT 'Indicates whether this period is the final period of the fiscal year requiring year-end close procedures, including balance sheet finalization, retained earnings posting, and annual financial statement preparation per FASB standards.',
    `ledger_group` STRING COMMENT 'SAP S/4HANA ledger group identifier that this period applies to (e.g., 0L for leading ledger, L1 for local GAAP ledger, L2 for IFRS ledger). Supports parallel accounting for multi-GAAP retail entities operating across jurisdictions.',
    `mm_posting_allowed` BOOLEAN COMMENT 'Indicates whether materials management (MM) postings — including goods receipts, inventory adjustments, and COGS postings — are permitted for this financial period in SAP S/4HANA MM module. Critical for inventory valuation and COGS accuracy.',
    `notes` STRING COMMENT 'Free-text notes or commentary associated with this financial period (e.g., Holiday season period — extended close window, Includes 53rd week adjustment, Restatement applied per ASC 606 guidance). Used by finance teams for period-specific documentation.',
    `period_close_date` DATE COMMENT 'The calendar date on which the financial period was officially closed in SAP S/4HANA FI, preventing further postings. Critical for financial close scheduling, audit compliance, and FASB revenue recognition cutoff enforcement.',
    `period_length_days` STRING COMMENT 'Number of calendar days in the financial period (typically 28 or 35 days for 4-week or 5-week NRF periods). Used for daily average calculations, proration of fixed costs, and lease accounting (ASC 842) period allocations.',
    `period_name` STRING COMMENT 'Human-readable name for the financial period (e.g., FY2024 Period 1, Q1 FY2024 Week 1, January 2024). Used in financial reports, P&L statements, and EBITDA dashboards for period labeling.',
    `period_number` STRING COMMENT 'Sequential period number within the fiscal year (1–12 for regular periods, 13–16 for special/adjustment periods). Maps to SAP S/4HANA posting period (MONAT) in table BKPF. Controls which periods are open for posting in the general ledger.',
    `period_open_date` DATE COMMENT 'The calendar date on which the posting period was officially opened for journal entry postings in SAP S/4HANA FI. Used for financial close audit trails and compliance with FASB reporting timelines.',
    `period_short_code` STRING COMMENT 'Standardized short code uniquely identifying the financial period across systems (e.g., FY2024P01, FY2024P13). Used as a business key for cross-system integration between SAP S/4HANA, Oracle Retail Merchandising System (ORMS), and financial reporting tools.. Valid values are `^FYd{4}Pd{2}$`',
    `period_type` STRING COMMENT 'Classification of the period by its accounting purpose. regular periods are standard operating periods; adjustment periods are used for year-end adjustments; closing periods are used for financial close entries; opening periods for balance carryforward; special for audit or correction postings.. Valid values are `regular|adjustment|closing|opening|special`',
    `posting_status` STRING COMMENT 'Current open/close status of the posting period in the general ledger. open allows new journal entries; closed prevents further postings; blocked restricts posting pending review; future indicates the period is not yet active. Controls SAP S/4HANA FI posting period management (OB52).. Valid values are `open|closed|blocked|future`',
    `quarter_name` STRING COMMENT 'Human-readable fiscal quarter label (e.g., Q1 FY2024, Q4 FY2023). Used in financial reporting dashboards, investor relations materials, and comparable store sales (SSS/Comp Sales) analysis.',
    `quarter_number` STRING COMMENT 'Fiscal quarter (1–4) to which this period belongs within the fiscal year. Used for quarterly P&L reporting, EBITDA tracking, and SEC/FASB quarterly financial disclosures.',
    `reopen_date` DATE COMMENT 'The date on which a previously closed financial period was reopened for additional postings or corrections. Populated only when close_status is reopened. Supports audit trail requirements for FASB restatements.',
    `reopen_reason` STRING COMMENT 'Business justification for reopening a previously closed financial period (e.g., Audit adjustment required, Revenue recognition restatement per ASC 606, Vendor chargeback correction). Required for SOX compliance and audit trail documentation.',
    `scheduled_close_date` DATE COMMENT 'The planned/target date for completing the financial close process for this period, as defined in the financial close calendar. Used to track close cycle performance and SLA adherence for the finance operations team.',
    `start_date` DATE COMMENT 'The first calendar date of the financial period. Defines the inclusive lower boundary for transaction posting, revenue recognition (ASC 606), and financial close scheduling.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this financial period record (e.g., status change, reopen event, close date update). Supports change data capture (CDC) in the Databricks Silver Layer and audit trail compliance.',
    `week_number` STRING COMMENT 'Fiscal week number within the fiscal year (1–52 or 1–53 for 53-week years). Critical for weekly retail performance reporting, same-store sales (SSS) comparisons, and Open-to-Buy (OTB) planning cycles.',
    CONSTRAINT pk_financial_period PRIMARY KEY(`financial_period_id`)
) COMMENT 'Fiscal calendar and financial period master defining the retail fiscal year structure (4-5-4 or 4-4-5 calendar), accounting periods, quarter boundaries, and year-end close dates. Includes period open/close status, period type (regular, adjustment, closing), and fiscal year variant. Controls posting periods in SAP S/4HANA FI and drives financial close scheduling.';

CREATE OR REPLACE TABLE `retail_ecm`.`finance`.`tax_posting` (
    `tax_posting_id` BIGINT COMMENT 'Unique identifier for the tax posting transaction record in SAP S/4HANA FI-TX.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Tax-exempt certificate validation and account-level nexus determination require linking tax postings to customer accounts. Retail tax compliance audits verify tax_exempt_certificate_number and tax_exe',
    `ap_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.ap_invoice. Business justification: Vendor invoices (AP) are a primary source of tax postings in retail — purchase tax, use tax, and VAT on vendor invoices must be tracked. Linking tax_posting.ap_invoice_id → ap_invoice.ap_invoice_id en',
    `ar_invoice_id` BIGINT COMMENT 'Foreign key linking to finance.ar_invoice. Business justification: Customer invoices (AR) generate sales tax and VAT postings in retail operations. Linking tax_posting.ar_invoice_id → ar_invoice.ar_invoice_id enables direct reconciliation of tax collected on customer',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Tax postings have cost_center (STRING) but no FK to cost_center master. This FK enables cost allocation for tax expenses.',
    `dc_facility_id` BIGINT COMMENT 'Foreign key linking to supplychain.dc_facility. Business justification: Sales and use tax postings by facility location for nexus determination, tax jurisdiction assignment, and compliance reporting. Required for multi-state retail tax compliance and audit defense.',
    `financial_period_id` BIGINT COMMENT 'Foreign key linking to finance.financial_period. Business justification: Tax postings must be associated with a financial period for period-end tax accruals, VAT return filing, and regulatory reporting. The existing reporting_period STRING is a denormalized text field that',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Tax postings have gl_account_number (STRING) but no FK to gl_account master. This FK enables account validation for tax postings.',
    `inbound_shipment_id` BIGINT COMMENT 'Foreign key linking to supplychain.inbound_shipment. Business justification: Cross-border retail inbound shipments trigger import duties, customs taxes, and freight taxes posted directly against the shipment. Tax authorities require shipment-level tax audit trails. tax_posting',
    `journal_entry_id` BIGINT COMMENT 'Foreign key linking to finance.journal_entry. Business justification: Tax postings in SAP S/4HANA are always generated as part of a GL document posting. Linking tax_posting.journal_entry_id → journal_entry.journal_entry_id provides direct traceability from the tax sub-l',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Tax postings in SAP S/4HANA are ledger-specific — tax amounts may differ between leading ledger (GAAP) and extension ledgers (IFRS, management). Linking tax_posting.ledger_id → ledger.ledger_id enable',
    `location_id` BIGINT COMMENT 'Unique identifier of the retail store location where the taxable transaction occurred (for POS sales tax postings).',
    `order_line_id` BIGINT COMMENT 'Foreign key linking to order.order_line. Business justification: Line-level tax compliance: e-commerce and omnichannel orders require per-line tax postings for multi-jurisdiction nexus reporting and ASC 740 compliance. Retail tax teams trace tax postings to origina',
    `original_posting_tax_posting_id` BIGINT COMMENT 'Reference to the original tax posting ID that this record reverses (populated only when reversal_flag is true).',
    `pos_transaction_id` BIGINT COMMENT 'Foreign key linking to order.pos_transaction. Business justification: Sales tax compliance: every POS transaction generates tax postings for jurisdiction-level remittance and audit. Tax authorities require transaction-level traceability. A retail tax compliance analyst ',
    `pos_transaction_line_id` BIGINT COMMENT 'Foreign key linking to order.pos_transaction_line. Business justification: POS line-level tax audit: each POS transaction line has its own tax_code and tax_rate; tax postings must trace to the specific line for sales tax audit defense, jurisdiction remittance, and tax-exempt',
    `profile_id` BIGINT COMMENT 'Unique identifier of the customer for output tax postings on sales transactions.',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Tax postings have profit_center (STRING) but no FK to profit_center master. This FK enables P&L allocation for tax expenses.',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to fulfillment.shipment. Business justification: Sales tax / VAT compliance: in retail, the taxable event is the shipment of goods to the customer. Tax authorities require traceability from tax postings to the shipment that triggered the tax obligat',
    `vendor_id` BIGINT COMMENT 'Unique identifier of the supplier/vendor for input tax postings on purchase transactions.',
    `audit_trail_reference` STRING COMMENT 'Cross-reference to supporting documentation for tax audit defense (original invoice, receipt, exemption certificate, tax calculation log).',
    `business_area` STRING COMMENT 'The business area code for cross-company-code financial reporting and segment analysis.. Valid values are `^[A-Z0-9]{4}$`',
    `company_code` STRING COMMENT 'The SAP company code representing the legal entity responsible for this tax posting.. Valid values are `^[A-Z0-9]{4}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this tax posting record was first created in the SAP S/4HANA FI-TX system.',
    `document_number` STRING COMMENT 'The externally-known accounting document number from which this tax posting originated (invoice, receipt, credit memo).. Valid values are `^[A-Z0-9]{10}$`',
    `document_type` STRING COMMENT 'Type of source accounting document that generated this tax posting.. Valid values are `invoice|credit_memo|debit_memo|payment|receipt|journal_entry`',
    `exchange_rate` DECIMAL(18,2) COMMENT 'Exchange rate used to convert transaction currency to local currency for GL posting.',
    `local_currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code of the companys local reporting currency for financial consolidation.. Valid values are `^[A-Z]{3}$`',
    `modified_timestamp` TIMESTAMP COMMENT 'The timestamp when this tax posting record was last modified (for correction postings or adjustments).',
    `nexus_indicator` BOOLEAN COMMENT 'Flag indicating whether the retailer has established tax nexus (physical or economic presence) in this jurisdiction, triggering tax collection obligation.',
    `posting_date` DATE COMMENT 'The date when the tax transaction was posted to the general ledger in SAP S/4HANA FI.',
    `reversal_flag` BOOLEAN COMMENT 'Indicates whether this posting is a reversal of a previously posted tax transaction (for corrections or cancellations).',
    `reverse_charge_flag` BOOLEAN COMMENT 'Indicates whether this is a reverse charge VAT transaction where the customer is responsible for self-assessing and remitting VAT.',
    `tax_amount` DECIMAL(18,2) COMMENT 'The calculated tax amount posted to the tax GL account, in transaction currency.',
    `tax_amount_local_currency` DECIMAL(18,2) COMMENT 'The tax amount converted to local reporting currency for financial statement consolidation.',
    `tax_authority_name` STRING COMMENT 'The name of the government tax authority to which this tax will be remitted (e.g., California Department of Tax and Fee Administration, IRS).',
    `tax_code` STRING COMMENT 'The SAP tax code that defines the tax type, rate, and GL account assignment for this posting.. Valid values are `^[A-Z0-9]{2,10}$`',
    `tax_determination_date` DATE COMMENT 'The business event date used to determine applicable tax rates and jurisdiction (typically transaction date or delivery date).',
    `tax_direction` STRING COMMENT 'Indicates whether this is input tax (paid to suppliers) or output tax (collected from customers).. Valid values are `input|output`',
    `tax_exempt_flag` BOOLEAN COMMENT 'Indicates whether this transaction qualified for tax exemption (e.g., resale certificate, government entity, non-profit exemption).',
    `tax_exemption_certificate_number` STRING COMMENT 'The exemption certificate number provided by the customer to support tax-exempt status (resale certificate, government ID, non-profit certificate).. Valid values are `^[A-Z0-9]{6,20}$`',
    `tax_jurisdiction_city` STRING COMMENT 'City or municipality name for city-level sales tax jurisdictions (applicable in US multi-jurisdiction tax scenarios).',
    `tax_jurisdiction_code` STRING COMMENT 'Composite jurisdiction code uniquely identifying the complete tax authority (country-state-county-city combination).. Valid values are `^[A-Z0-9]{4,15}$`',
    `tax_jurisdiction_country` STRING COMMENT 'Three-letter ISO country code of the tax jurisdiction where the tax obligation arises.. Valid values are `^[A-Z]{3}$`',
    `tax_jurisdiction_county` STRING COMMENT 'County or district name for county-level sales tax jurisdictions (applicable in US multi-jurisdiction tax scenarios).',
    `tax_jurisdiction_state` STRING COMMENT 'Two-letter state or province code within the country for state-level sales tax (US) or provincial tax (Canada).. Valid values are `^[A-Z]{2}$`',
    `tax_point_date` DATE COMMENT 'The date when the tax liability arises for VAT purposes (typically invoice date or goods delivery date per VAT regulations).',
    `tax_rate_percentage` DECIMAL(18,2) COMMENT 'The effective tax rate percentage applied to the taxable base (e.g., 8.25000 for 8.25% sales tax).',
    `tax_registration_number` STRING COMMENT 'The retailers tax registration number with the jurisdictions tax authority (sales tax permit number, VAT registration number, GST number).. Valid values are `^[A-Z0-9]{6,20}$`',
    `tax_type` STRING COMMENT 'The category of tax being posted (sales tax, VAT, use tax, excise duty, withholding tax, customs duty).. Valid values are `sales_tax|use_tax|vat|excise_duty|withholding_tax|customs_duty`',
    `taxable_base_amount` DECIMAL(18,2) COMMENT 'The gross transaction amount subject to tax before tax calculation, in transaction currency.',
    `transaction_currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which the tax transaction was recorded.. Valid values are `^[A-Z]{3}$`',
    CONSTRAINT pk_tax_posting PRIMARY KEY(`tax_posting_id`)
) COMMENT 'Tax transaction record capturing sales tax, VAT, use tax, and excise duty postings on retail transactions in SAP S/4HANA FI-TX. Includes tax code, tax jurisdiction (state/county/city/country), taxable base amount, tax amount, tax rate, tax type (input/output), tax determination date, reporting period, nexus indicator, exempt flag, and source document reference. Supports multi-jurisdiction sales tax compliance, Streamlined Sales Tax (SST) reporting, tax return preparation, tax audit defense, and regulatory reporting to federal, state, and local tax authorities.';

CREATE OR REPLACE TABLE `retail_ecm`.`finance`.`ledger` (
    `ledger_id` BIGINT COMMENT 'Primary key for ledger',
    `parent_ledger_id` BIGINT COMMENT 'Self-referencing FK on ledger (parent_ledger_id)',
    `accounting_standard` STRING COMMENT 'The accounting standard or framework that governs this ledger (e.g., US GAAP, IFRS).',
    `company_code` STRING COMMENT 'The legal entity or company code to which this ledger belongs in the enterprise structure.',
    `consolidation_version` STRING COMMENT 'Version identifier for consolidation scenarios when this ledger is used for group reporting.',
    `controlling_area` STRING COMMENT 'The controlling area code for management accounting and cost center reporting associated with this ledger.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this ledger record was first created in the system.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code representing the functional currency of the ledger.',
    `effective_end_date` DATE COMMENT 'The date on which this ledger ceases to be active for new postings. Null indicates an open-ended ledger.',
    `effective_start_date` DATE COMMENT 'The date from which this ledger becomes active and available for financial postings.',
    `fiscal_year_variant` STRING COMMENT 'Code representing the fiscal calendar variant used by this ledger (e.g., calendar year, 4-4-5 retail calendar).',
    `is_consolidation_ledger` BOOLEAN COMMENT 'Boolean flag indicating whether this ledger is used for group consolidation and intercompany elimination purposes.',
    `is_leading_ledger` BOOLEAN COMMENT 'Boolean flag indicating whether this is the primary leading ledger for the organization (true) or a secondary/parallel ledger (false).',
    `last_closed_date` DATE COMMENT 'The date when the most recent period close was completed for this ledger.',
    `last_closed_period` STRING COMMENT 'The most recent fiscal period (YYYYMM format) that has been closed in this ledger.',
    `ledger_category` STRING COMMENT 'High-level categorization of the ledger based on reporting purpose and accounting framework alignment.',
    `ledger_code` STRING COMMENT 'Unique business identifier code for the ledger used in financial reporting and system integration.',
    `ledger_description` STRING COMMENT 'Detailed textual description of the ledger purpose, scope, and usage within the financial reporting framework.',
    `ledger_name` STRING COMMENT 'Full descriptive name of the ledger for human-readable identification.',
    `ledger_status` STRING COMMENT 'Current operational status of the ledger in the financial system lifecycle.',
    `ledger_type` STRING COMMENT 'Classification of the ledger based on its functional purpose in the financial accounting system.',
    `modified_by` STRING COMMENT 'User identifier or name of the person who last modified this ledger record.',
    `modified_timestamp` TIMESTAMP COMMENT 'The date and time when this ledger record was last modified in the system.',
    `posting_period_variant` STRING COMMENT 'Code defining the number and structure of posting periods (e.g., 12 regular periods plus special periods) for this ledger.',
    `profit_loss_account` STRING COMMENT 'General ledger account number used for profit and loss statement aggregation.',
    `retained_earnings_account` STRING COMMENT 'General ledger account number used for retained earnings carry-forward during year-end closing.',
    `supports_cost_center` BOOLEAN COMMENT 'Boolean flag indicating whether this ledger supports cost center accounting for overhead allocation and analysis.',
    `supports_profit_center` BOOLEAN COMMENT 'Boolean flag indicating whether this ledger supports profit center accounting for internal management reporting.',
    `supports_segment_reporting` BOOLEAN COMMENT 'Boolean flag indicating whether this ledger supports segment-level financial reporting as required by FASB ASC 280.',
    `valuation_view` STRING COMMENT 'The valuation perspective or view that this ledger represents for parallel accounting purposes.',
    `created_by` STRING COMMENT 'User identifier or name of the person who created this ledger record in the system.',
    CONSTRAINT pk_ledger PRIMARY KEY(`ledger_id`)
) COMMENT 'Master reference table for ledger. Referenced by ledger_id.';

-- ========= FOREIGN KEYS =========
ALTER TABLE `retail_ecm`.`finance`.`cost_center` ADD CONSTRAINT `fk_finance_cost_center_gl_account_id` FOREIGN KEY (`gl_account_id`) REFERENCES `retail_ecm`.`finance`.`gl_account`(`gl_account_id`);
ALTER TABLE `retail_ecm`.`finance`.`cost_center` ADD CONSTRAINT `fk_finance_cost_center_profit_center_id` FOREIGN KEY (`profit_center_id`) REFERENCES `retail_ecm`.`finance`.`profit_center`(`profit_center_id`);
ALTER TABLE `retail_ecm`.`finance`.`profit_center` ADD CONSTRAINT `fk_finance_profit_center_gl_account_id` FOREIGN KEY (`gl_account_id`) REFERENCES `retail_ecm`.`finance`.`gl_account`(`gl_account_id`);
ALTER TABLE `retail_ecm`.`finance`.`journal_entry` ADD CONSTRAINT `fk_finance_journal_entry_cost_center_id` FOREIGN KEY (`cost_center_id`) REFERENCES `retail_ecm`.`finance`.`cost_center`(`cost_center_id`);
ALTER TABLE `retail_ecm`.`finance`.`journal_entry` ADD CONSTRAINT `fk_finance_journal_entry_financial_period_id` FOREIGN KEY (`financial_period_id`) REFERENCES `retail_ecm`.`finance`.`financial_period`(`financial_period_id`);
